--
-- Table structure for table `bundles`
--

CREATE TABLE `bundles` (
  `id` int UNSIGNED NOT NULL,
  `creator_id` int UNSIGNED NOT NULL,
  `teacher_id` int UNSIGNED NOT NULL,
  `category_id` int UNSIGNED DEFAULT NULL,
