INSERT INTO `page_translations` (`id`, `page_id`, `locale`, `title`, `seo_description`, `content`) VALUES
(1, 3, 'en', 'Kemecademy.com The first Real estate academy', 'KEMECADEMY is the first online & offline course marketplace to connect instructors & students in all real estate sectors.', '<p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">KEMECADEMY is the first online & in-person classroom course marketplace and platform to connect instructors & students in all real estate sectors. Like all systems of Kemedar, This platform helps instructors and students get in touch together and share knowledge.</span></p><p dir=\"ltr\" style=\"margin-top: 0pt; margin-bottom: 0pt; line-height: 1.38;\"><b style=\"font-weight:normal;\" id=\"docs-internal-guid-a7dcb5d8-7fff-0759-f9b1-a9742e6010c8\"><br></b></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">KEMECADEMY is based on real estate business needs, advanced user researches so it covers your requirements efficiently.</span></p><p dir=\"ltr\" style=\"margin-top: 0pt; margin-bottom: 0pt; line-height: 1.38;\"><b style=\"font-weight:normal;\"><br></b></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Our mission is to enhance the technical and professional skills of people in the real estate industry, by providing an easy-to-use platform through which anyone can share his expertise by giving paid or free courses.</span></p><p dir=\"ltr\" style=\"margin-top: 0pt; margin-bottom: 0pt; line-height: 1.38;\"><b style=\"font-weight:normal;\"><br></b></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">KEMECADEMY strive to benefit all those working in the real estate industry as:</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Handymen & Professionals</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Realestate Agents</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Realestate Developers</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Project managers.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Investors</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Realestate Entrepreneurs</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Realestate Marketers</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Realestate Consultants</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Realestate Tutors</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Youth & Students</span></p><p dir=\"ltr\" style=\"margin-top: 0pt; margin-bottom: 0pt; line-height: 1.38;\"><b style=\"font-weight:normal;\"><br></b></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Professional instructors and tutors with great experience who like to give their experiences to benefit others. Many of them are volunteers and their courses are free of charge for the Academy\'s students..</span></p><p dir=\"ltr\" style=\"margin-top: 0pt; margin-bottom: 0pt; line-height: 1.38;\"><b style=\"font-weight:normal;\"><br></b></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Tutors & instructors will be able to create unlimited video courses, live classes, text courses, projects, quizzes, files, ...etc and students will be able to use the educational material and increase their skill level.</span></p><p dir=\"ltr\" style=\"margin-top: 0pt; margin-bottom: 0pt; line-height: 1.38;\"><b style=\"font-weight:normal;\"><br><br></b></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">WHY CHOOSE KEMECADEMY?</span></p><p dir=\"ltr\" style=\"margin-top: 0pt; margin-bottom: 0pt; line-height: 1.38;\"><b style=\"font-weight:normal;\"><br></b></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Dedicated in Real estate industry</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Integrated with other systems in kemedar.com</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Comprehensive solution for online & offline</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Based on real estate business needs</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:11pt;font-family:Arial;color:#000000;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">- Special training packages for Real estate companies</span></p><p dir=\"ltr\" style=\"margin-top: 0pt; margin-bottom: 0pt; line-height: 1.38;\"><b style=\"font-weight:normal;\"><br><br></b></p><h2 dir=\"ltr\" style=\"line-height:1.7999999999999998;border-bottom:solid #d4d4d4 0.75pt;margin-top:23pt;margin-bottom:15pt;padding:0pt 0pt 7.5pt 0pt;\"><span style=\"font-size:15pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">FEATURES</span></h2><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">KEMECADEMY</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> is packed with a lot of useful features. You can view key features in the following list:</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Multiple content support:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> KEMECADEMY supports multiple content types such as video courses, live classes , text-based courses, SCORM courses , and articles. Instructors can select any type of content they would like</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Organizational education:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> KEMECADEMY supports organizations and institutes so you can define organizations and institutes with related students and instructors. Organizations can define different prices for their own students.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Online meetings:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> In addition to educational materials, instructors and organizations will be able to sell online meetings and students will be able to book online, in-person, and group meetings..This feature developed with real estate consultant in mind. It is great feature for consultant and tutore that would like to sell their consultation by hour price</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Payment gateways:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> There are 30 gateways supported for different countries. Paypal, Stripe, XeedWallet, Razorpay, Paytm, PayU, Paystack, Zarinpal, Paysera, CashU, Robokassa, Mercadopago, Bitpay, Midtrans, Flutterwave, Payfort, Braintree, Mollie, Alipay, Authorize.net, Instamojo, Izipay, Klarna, N-genius, Payku, Paylink, Sslcommerz, Payhere, Toyyibpay, Voguepay, JazzCash, Paysera. Offline payments. This will make instructor accept all types of payments when he add his course on Kemecademy</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Youtube & Vimeo support:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Instructors can use Vimeo & Youtube video links as of course parts so they could be used as free and safe video storage.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Social & SMS login:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Users can log in to the system using social accounts (Google & Facebook) also SMS and login are supported. This will make registration at a matter of seconds to make it easy for all users</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Subscription system:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> In addition to normal purchases using the cart, students will be able to subscribe to courses by purchasing different subscription plans. Instructors can put their own subscription plans for their courses</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Google Calendar integration:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> KEMECADEMY is integrated with Google calendar so users will be able to add all of the events such as live class sessions, meetings, etc to the Google calendar and events will be reminded to them automatically so nothing will be missed.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Accounting system:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> KEMECADEMY includes a built-in accounting system that provides transaction tracking, sales analysis, advanced reports, refunds, manual accounting, payouts, invoices, offline payments, etc. Instructors will be peace of mind of all accounting operations and just focus on their courses quality</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Variable commission rates:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Variable commission rates. We have extra commission rates for most active instructors and encourage them.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Quiz and certification:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Instructors can create unlimited quizzes and certificates and assign them to the courses. You can define video and image quizzes in addition to the text quizzes. KEMECADEMY includes an advanced certification system that allows you to create quiz-depended certificates & course completion certificates.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Badges and rewarding system: </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">KEMECADEMY has different badges related to the instructor’s actions. Badges will be assigned to instructors automatically.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Marketing options:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> There are several marketing features such as advanced discount codes, content promotions, featured classes, course discounts, advertising banners & modals, email newsletters, etc to perform marketing campaigns. This will support instructors do the promotion of their courses in their own channels very easily too</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Notifications:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Automatic notifications will be sent after each related process. Instructors can also send promotional & customized notifications to his students.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Support system:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Students will be able to get in touch with instructors within a clear and functional course support system. Users can create support tickets for the admin as well.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Separate panels:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> KEMECADEMY includes separate panels for instructors, students, and organizations with different data types.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Offline payments:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Users will be able to charge their accounts using an offline payment system and the money will be added to their account after admin approval.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Class options:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> There are many options for each class such as class capacity, private classes, class start date, class reports, FAQ, filters, rating, invited instructors, etc that help instructors to create professional educational material for different educational needs.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Course Sections:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Instructors can organize course materials in different sections and chapters.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Noticeboard:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Instructors can send personalized notices to students and display notices on the noticeboard.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Multi-language Content:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Our system is multilingual. The content will be loaded according to the user’s language.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Affiliate & Referral Marketing:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> We have our own affiliate marketing system. Users will be able to sell your courses and earn. This will increase your return very effeciently</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">SCORM Courses: </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Bring the interactive educational experience. Instructors can publish courses made by Adobe Captive, iSpring, or any other software.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">In-App Live Class System:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Conduct live classes on KEMECADEMY </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">directly </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">with awesome features like live chat, share screen, etc. Your student won’t be redirected to any other third-party app. Imagine a live class screen on your KEMECADEMY dashboard without going anywhere.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Kemecoin Points System:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> KEMECADEMY users will get points according to their different activities like purchasing, charging account, publishing courses, passing a quiz, certificate achievement, comments, course reviews, joining the newsletter, referring users (Affiliate), getting badges, course completion and meeting reservation. Users will be able to enroll in courses using points or convert them to account balance.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Tutor Finder:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Allows students to find the best instructors according to different parameters like tutoring level, tutoring subject, meeting type (Online, In-person), meeting time and day, location on the map, age, and gender. This feature includes a beautiful wizard that gets information from the student and will display the best matches.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Forum & Community: </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Users will be able to create new topics in different categories and communicate together about different subjects in real estate industry.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Course Forum: </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Allow course students to ask their questions in the course forum. Other students and the instructor will be able to answer questions. Students can mark resolved questions as “Resolved”.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Course Bundle: </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can combine several courses as a bundle and sell them together as a bundle.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Store & Marketplace: </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">This is multi-vendor marketplace and store feature that allow instructors to sell physical & virtual products. Like tools, books and materials needed with their courses</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Drip Content: </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can restrict the student’s access to the course chapters and files by different limitation parameters like time and sequence content. Instructors can define forcing students to access course parts X days after purchasing the course or forcing them to pass the previous part.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Manual Enrolment: </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can add students to courses, bundles, and products manually.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Assignment & Homework:  </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can define different assignments for each course with different options like grade, deadline, etc, and make the education process more effective.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Course Statistics & Analytics:  </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can view course details and statistics in a graphical environment.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Course Noticeboard:  </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can send different notices to the course students in different colors.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">In-app Video Call:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Enjoy the in-app video call experience for conducting meetings directly on KEMEKADEMY. Let users book meetings on the platform and conduct peer-to-peer or group video calls directly on the platform. No need to use any other video calling solution for conducting meetings.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Cashback:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> We offer users to make purchases and recharge a specific percentage or fixed amount to their wallets after making purchases. </span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Question Bank:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can define different questions for a quiz and display a specific number of questions to students randomly or sorted. Conduct more accurate quizzes using this feature by presenting random questions to students.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Upcoming Courses:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Let our platform stendents know about your upcoming courses. Students can follow upcoming courses and they will get informed about the course publishing after publishing the course. Get your course early adaptors before publishing the course.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Installments and Partial Payment:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Instructors can sell different materials like courses using the installment (Partial Payment) and define upfront, payment steps, and duration. Disable platform or course access for overdue installments. The system will send payment reminders for each payment.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Secure Host:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Are you worried about your videos and courses for unwanted access or downloading and spreading? </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can use this feature to preserve your video content from unwanted downloads.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Jitsi Meetings:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Conduct live classes directly on Jitsi and enjoy a low-latency live video experience.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Course Waitlist:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can turn on the waitlist feature for your course and never miss potential students for your courses. Users can join your course waitlist when the capacity is reached or the course is in progress. Inform your waitlist users of future events.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Gift Products:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Allow users to send courses or other materials as gifts to their friends immediately or on a specific date. The recipient will get an email for receiving the gift.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Multi-currency:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can sell their courses in different currencies and convert course prices according to the selected currency. Make specific payment gateways available for each currency. This feature allow you expand your business worldwide.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Device Limit:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Resctict the number of logged-in sessions for users and avoid sharing accounts between users. This is important to secure instructors’s rights.</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Auto Content Approval:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> Instructor-created data (Courses, contents, etc) will be published automatically without admin approval. This will be available for some instructors with some rules</span></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Private Courses:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can create private courses that won’t be displayed on the platform and the admin can add students to them from the admin panel manually.</span></p><p dir=\"ltr\" style=\"margin-top: 0pt; margin-bottom: 0pt; line-height: 1.38;\"></p><p dir=\"ltr\" style=\"line-height:1.38;margin-top:0pt;margin-bottom:15pt;\"><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Course Capacity:</span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:700;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"> </span><span style=\"font-size:12pt;font-family:Arial;color:#545454;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Instructors can define a specific capacity for all course types so only a limited number of users can enroll in the course.</span></p>');
INSERT INTO `page_translations` (`id`, `page_id`, `locale`, `title`, `seo_description`, `content`) VALUES
(2, 5, 'en', 'Terms & Conditions', 'KEMECADEMY is the first online & in-person classroom course marketplace and platform to connect instructors & students in all real estate sectors.', '<p dir=\"ltr\" style=\"line-height:1.3800000000000001;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;padding:0pt 0pt 10pt 0pt;\"><span style=\"font-size:18pt;font-family:inherit;color:#555555;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Terms & Conditions</span></p><p><span id=\"docs-internal-guid-39bf3966-7fff-5f1c-1209-6593479f9c5c\"></span></p><p dir=\"ltr\" style=\"line-height:1.3800000000000001;background-color:#ffffff;margin-top:0pt;margin-bottom:0pt;\"><span style=\"font-size:10.5pt;font-family:Arial;color:#555555;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">The term \"KEMEDAR.COM\" or \"us\" or \"we\" refers to the owners of KEMEDAR.COM. The term \"you\" refers to the user or viewer of our website. The use of this website is subject to the following terms of use:</span><span style=\"font-size:10.5pt;font-family:Arial;color:#555555;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span><span style=\"font-size:10.5pt;font-family:Arial;color:#555555;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span><span style=\"font-size:10.5pt;font-family:Arial;color:#555555;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">The content of the pages of this website is for your general information and use only. It is subject to change without notice.</span><span style=\"font-size:10.5pt;font-family:Arial;color:#555555;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span><span style=\"font-size:10.5pt;font-family:Arial;color:#555555;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Neither we nor any third parties provide any warranty or guarantee as to the accuracy, timeliness, performance, completeness or suitability of the information and materials found or offered on this website for any particular purpose. You acknowledge that such information and materials may contain inaccuracies or errors and we expressly exclude liability for any such inaccuracies or errors to the fullest extent permitted by law.</span><span style=\"font-size:10.5pt;font-family:Arial;color:#555555;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span><span style=\"font-size:10.5pt;font-family:Arial;color:#555555;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\">Your use of any information or materials on this website is entirely at your own risk, for which we shall not be liable. It shall be your own responsibility to ensure that any products, services, or information available through this website meet your specific requirements.</span><span style=\"font-size:10.5pt;font-family:Arial;color:#555555;background-color:transparent;font-weight:400;font-style:normal;font-variant:normal;text-decoration:none;vertical-align:baseline;white-space:pre;white-space:pre-wrap;\"><br></span><span style=\"