  `id` int UNSIGNED NOT NULL,
  `selected_installment_id` int UNSIGNED NOT NULL,
  `installment_step_id` int UNSIGNED NOT NULL,
  `deadline` int UNSIGNED DEFAULT NULL,
  `amount` double(15,2) DEFAULT NULL,
