(20, 4, 'en', '{\"first_column\":{\"title\":\"Our Mission\",\"value\":\"<p><font color=\\\"#ffffff\\\">Our mission is to enhance the technical and professional skills of people in the real estate industry, by providing an easy-to-use platform through which anyone can share his expertise by giving paid or free courses.<\\/font><\\/p><p><font color=\\\"#ffffff\\\"><br><\\/font><\\/p><h6 style=\\\"text-align: center; \\\"><a href=\\\"\\/pages\\/about\\\" target=\\\"_blank\\\"><font color=\\\"#ffffff\\\"><b>More information<\\/b><\\/font><\\/a><\\/h6>\"},\"second_column\":{\"title\":\"Target audience\",\"value\":\"<p><font color=\\\"#ffffff\\\">- Handymen &amp; Professionals<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Realestate Agents<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Realestate Developers<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Project managers.<\\/font><\\/p><p><font color=\\\"#ffffff\\\">-&nbsp;Realestate&nbsp;Investors<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Realestate Entrepreneurs<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Realestate Marketers<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Realestate Consultants<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Realestate Tutors<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Youth &amp; Students<\\/font><\\/p>\"},\"third_column\":{\"title\":\"Top Categories\",\"value\":\"<p><font color=\\\"#ffffff\\\">- Home decoration<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Painting<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Carpenting<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Lanscaping<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Plumbing<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Tiles works<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Electricity<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Courses for kids<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Marketing<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Project Management<\\/font><\\/p>\"},\"forth_column\":{\"tit