(50, 4, 'es', '{\"first_column\":{\"title\":\"Nuestra misi\\u00f3n\",\"value\":\"<p><font color=\\\"#ffffff\\\">Nuestra misi\\u00f3n es mejorar las habilidades t\\u00e9cnicas y profesionales de las personas en la industria de bienes ra\\u00edces, proporcionando una plataforma f\\u00e1cil de usar a trav\\u00e9s de la cual cualquier persona puede compartir su experiencia dando cursos pagos o gratuitos.<\\/font><\\/p><p><font color=\\\"#ffffff\\\"><br><\\/font><\\/p><p style=\\\"text-align: center; \\\"><b><a href=\\\"\\/pages\\/about\\\" target=\\\"_blank\\\"><font color=\\\"#ffffff\\\">M\\u00e1s informaci\\u00f3n<\\/font><\\/a><\\/b><\\/p>\"},\"second_column\":{\"title\":\"P\\u00fablico objetivo\",\"value\":\"<p><span style=\\\"color: rgb(255, 255, 255);\\\">- Manitas Inmobiliarias<\\/span><\\/p><p><font color=\\\"#ffffff\\\">- Agentes de Bienes Raices<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Promotores inmobiliarios<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Gestores de proyectos inmobiliarios.<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Inversores inmobiliarios<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Emprendedores inmobiliarios<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Comercializadores inmobiliarios<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Consultores inmobiliarios<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Tutores Inmobiliarios<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- J\\u00f3venes y Estudiantes<\\/font><\\/p>\"},\"third_column\":{\"title\":\"Categor\\u00edas principales\",\"value\":\"<p><span style=\\\"color: rgb(255, 255, 255);\\\">- Decoraci\\u00f3n hogare\\u00f1a<\\/span><\\/p><p><font color=\\\"#ffffff\\\">- Pintura mural<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Trabajos de carpinter\\u00eda<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Paisajismo<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Trabajos de plomer\\u00eda<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Trabajos de azulejos<\\/font><\\/p><p><font c