(54, 32, 'es', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"Encuentra el mejor instructor, consultor o tutor\",\"description\":\"\\u00bfBuscas un instructor, consultor o tutor? Encuentre el mejor seg\\u00fan diferentes par\\u00e1metros como g\\u00e9nero, nivel de habilidad, precio, tipo de reuni\\u00f3n, calificaci\\u00f3n, etc.\",\"button1\":{\"title\":\"Asistente de b\\u00fasqueda\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"En el mapa\",\"link\":\"\\/instructor-finder\"}}'),
(55, 33, 'ar', '{\"image\":\"\\/store\\/1\\/general images\\/club-points.png\",\"title\":\"\\u0627\\u0631\\u0628\\u062d \\u0643\\u064a\\u0645\\u064a\\u0643\\u0648\\u064a\\u0646\",\"description\":\"\\u0627\\u0633\\u062a\\u062e\\u062f\\u0645 \\u0643\\u064a\\u0645\\u064a\\u0643\\u0627\\u062f\\u064a\\u0645\\u064a \\u0648\\u0627\\u0631\\u0628\\u062d \\u0643\\u064a\\u0645\\u064a\\u0643\\u0648\\u064a\\u0646 \\u0648\\u0641\\u0642\\u064b\\u0627 \\u0644\\u0644\\u0623\\u0646\\u0634\\u0637\\u0629 \\u0627\\u0644\\u0645\\u062e\\u062a\\u0644\\u0641\\u0629 \\u060c \\u0633\\u062a\\u062a\\u0645\\u0643\\u0646 \\u0645\\u0646 \\u0627\\u0633\\u062a\\u062e\\u062f\\u0627\\u0645 \\u0639\\u0645\\u0644\\u0627\\u062a\\u0643 \\u0627\\u0644\\u0645\\u0639\\u062f\\u0646\\u064a\\u0629 \\u0644\\u0644\\u062d\\u0635\\u0648\\u0644 \\u0639\\u0644\\u0649 \\u062c\\u0648\\u0627\\u0626\\u0632 \\u0648\\u062f\\u0648\\u0631\\u0627\\u062a \\u0645\\u062c\\u0627\\u0646\\u064a\\u0629. \\u0627\\u0628\\u062f\\u0623 \\u0641\\u064a \\u0627\\u0633\\u062a\\u062e\\u062f\\u0627\\u0645 \\u0627\\u0644\\u0646\\u0638\\u0627\\u0645 \\u0627\\u0644\\u0622\\u0646 \\u0648\\u0627\\u062c\\u0645\\u0639 \\u0639\\u0645\\u0644\\u0627\\u062a \\u0643\\u064a\\u0645\\u064a\\u0643\\u0648\\u064a\\u0646!\",\"button1\":{\"title\":\"\\u0627\\u0644\\u0645\\u0643\\u0627\\u0641\\u0622\\u062a\",\"link\":\"\\/reward-courses\"},\"button2\":{\"title\":\"\\u0643\\u064a\\u0645\\u064a\\u0643\\u0648\\u064a\\u0646 \\u062e\\u0627\\u0635\\u062a\\u0643\",\"link\":\"\\/panel\\/rewards\"}}'),
(56, 33, 'es', '{\"image\":\"\\/store\\/1\\/general images\\/club-points.png\",\"title\":\"Gana Kemecoins\",\"description\":\"Usa Kemecademy y gana Kemecoins seg\\u00fan diferentes actividades. Podr\\u00e1s usar tus monedas para obtener premios y cursos gratis. \\u00a1Empieza a usar el sistema ahora y recoge monedas!\",\"button1\":{\"title\":\"Recompensas\",\"link\":\"\\/reward-courses\"},\"button2\":{\"title\":\"Tus Kemecoins\",\"link\":\"\\/panel\\/rewards\"}}'),
