(79, 8, 'zh', '{\"title\":\"\\u6bcf\\u4e2a\\u4eba\\u90fd\\u6709\\u53ef\\u4ee5\\u6559\\u7684\\u4e1c\\u897f\\u3002 \\u6bcf\\u4e2a\\u4eba\\u90fd\\u9700\\u8981\\u5b66\\u4e60\\u7684\\u4e1c\\u897f\",\"description\":\"\\u6211\\u4eec\\u5728 Kemecademy \\u7684\\u4f7f\\u547d\\u662f\\u63d0\\u9ad8\\u6240\\u6709\\u5728\\u623f\\u5730\\u4ea7\\u884c\\u4e1a\\u5de5\\u4f5c\\u7684\\u4eba\\u7684\\u6280\\u672f\\u548c\\u4e13\\u4e1a\\u6c34\\u5e73\\uff0c\\u4ece\\u5de5\\u5320\\u548c\\u6280\\u672f\\u4eba\\u5458\\u5230\\u8425\\u9500\\u4eba\\u5458\\u548c\\u81ea\\u7531\\u804c\\u4e1a\\u8005\\u3002 \\u623f\\u5730\\u4ea7\\u7ecf\\u7eaa\\u4eba\\u548c\\u6295\\u8d44\\u8005\\u4e5f\\u53ef\\u4ee5\\u5229\\u7528\\u4e13\\u95e8\\u7684\\u8ba1\\u5212\\u3002 Kemecademy \\u7684\\u8bb2\\u5e08\\u90fd\\u662f\\u7ecf\\u9a8c\\u4e30\\u5bcc\\u7684\\u4e13\\u4e1a\\u4eba\\u58eb\\uff0c\\u4ed6\\u4eec\\u559c\\u6b22\\u4e0e\\u4ed6\\u4eba\\u5206\\u4eab\\u4ed6\\u4eec\\u7684\\u7ecf\\u9a8c\\u3002 \\u4ed6\\u4eec\\u7684\\u8bb8\\u591a\\u8bfe\\u7a0b\\u90fd\\u662f\\u514d\\u8d39\\u7684\\u3002 \\u5e74\\u8f7b\\u4eba\\u548c\\u513f\\u7ae5\\u53ef\\u4ee5\\u4ece\\u4e13\\u95e8\\u7684\\u57f9\\u8bad\\u8ba1\\u5212\\u4e2d\\u53d7\\u76ca\",\"hero_background\":\"\\/store\\/1\\/general images\\/hero.jpg\",\"is_video_background\":\"0\"}'),
(80, 8, 'fr', '{\"title\":\"Tout le monde a quelque chose \\u00e0 enseigner. Tout le monde a besoin de quelque chose \\u00e0 apprendre\",\"description\":\"Notre mission chez Kemecademy est d\'\\u00e9lever le niveau technique et professionnel de tous ceux qui travaillent dans le secteur de l\'immobilier, des artisans et techniciens aux sp\\u00e9cialistes du marketing et aux ind\\u00e9pendants. Les agents immobiliers et les investisseurs peuvent \\u00e9galement profiter de programmes sp\\u00e9cialis\\u00e9s. Les instructeurs de Kemecademy sont tous des professionnels avec une grande exp\\u00e9rience qui aiment partager leurs exp\\u00e9riences avec les autres. Beaucoup de leurs cours sont gratuits. Les jeunes et les enfants peuvent b\\u00e9n\\u00e9ficier de programmes de formation sp\\u00e9cialis\\u00e9s\",\"hero_background\":\"\\/store\\/1\\/general images\\/hero.jpg\",\"is_video_background\":\"0\"}'),
(81, 8, 'de', '{\"title\":\"Jeder hat etwas zu lehren. Jeder muss etwas lernen\",\"description\":\"Unsere Mission bei Kemecademy ist es, das technische und berufliche Niveau aller in der Immobilienbranche T\\u00e4tigen anzuheben, von Handwerkern und Technikern bis hin zu Vermarktern und Freiberuflern. Immobilienmakler und Investoren k\\u00f6nnen auch von spezialisierten Programmen profitieren. Die Ausbilder der Kemecademy sind alle Profis mit gro\\u00dfer Erfahrung, die ihre Erfahrungen gerne mit anderen teilen. Viele ihrer Kurse sind kostenlos. Jugendliche und Kinder k\\u00f6nnen von speziellen Trainingsprogrammen profitieren\",\"hero_background\":\"\\/store\\/1\\/general images\\/hero.jpg\",\"is_video_background\":\"0\"}'),
(82, 8, 'hi', '{\"title\":\"\\u0939\\u0930 \\u0915\\u093f\\u0938\\u0940 \\u0915\\u0947 \\u092a\\u093e\\u0938 \\u0938\\u093f\\u0916\\u093e\\u0928\\u0947 \\u0915\\u0947 \\u0932\\u093f\\u090f \\u0915\\u0941\\u091b \\u0928 \\u0915\\u0941\\u091b \\u0939\\u094b\\u0924\\u093e \\u0939\\u0948\\u0964 \\u0938\\u092d\\u0940 \\u0915\\u094b \\u0915\\u0941\\u091b \\u0928 \\u0915\\u0941\\u091b \\u0938\\u0940\\u0916\\u0928\\u0947 \\u0915\\u0940 \\u091c\\u0930\\u0942\\u0930\\u0924 \\u0939\\u0948\",\"description\":\"\\u0915\\u0947\\u092e\\u0947\\u0915\\u0948\\u0921\\u0940 \\u092e\\u0947\\u0902 \\u0939\\u092e\\u093e\\u0930\\u093e \\u092e\\u093f\\u0936\\u0928 \\u0936\\u093f\\u0932\\u094d\\u092a\\u0915\\u093e\\u0930\\u094b\\u0902 \\u0914\\u0930 \\u0924\\u0915\\u0928\\u0940\\u0936\\u093f\\u092f\\u0928\\u094b\\u0902 \\u0938\\u0947 \\u0932\\u0947\\u0915\\u0930 \\u0935\\u093f\\u092a\\u0923\\u0915 \\u0914\\u0930 \\u092b\\u094d\\u0930\\u0940\\u0932\\u093e\\u0902\\u0938\\u0930\\u094b\\u0902 \\u0924\\u0915 \\u0930\\u093f\\u092f\\u0932 \\u090f\\u0938\\u094d\\u091f\\u0947\\u091f \\u0909\\u0926\\u094d\\u092f\\u094b\\u0917 \\u092e\\u0947\\u0902 \\u0915\\u093e\\u092e \\u0915\\u0930\\u0928\\u0947 \\u0935\\u093e\\u0932\\u0947 \\u0938\\u092d\\u0940 \\u0932\\u094b\\u0917\\u094b\\u0902 \\u0915\\u0947 \\u0924\\u0915\\u0928\\u0940\\u0915\\u0940 \\u0914\\u0930 \\u092a\\u0947\\u0936\\u0947\\u0935\\u0930 \\u0938\\u094d\\u0924\\u0930 \\u0915\\u094b \\u090a\\u092a\\u0930 \\u0909\\u0920\\u093e\\u0928\\u093e \\u0939\\u0948\\u0964 \\u0930\\u093f\\u092f\\u0932 \\u090f\\u0938\\u094d\\u091f\\u0947\\u091f \\u090f\\u091c\\u0947\\u0902\\u091f \\u0914\\u0930 \\u0928\\u093f\\u0935\\u0947\\u0936\\u0915 \\u092d\\u0940 \\u0935\\u093f\\u0936\\u0947\\u0937 \\u0915\\u093e\\u0930\\u094d\\u092f\\u0915\\u094d\\u0930\\u092e\\u094b\\u0902 \\u0915\\u093e \\u0932\\u093e\\u092d \\u0909\\u0920\\u093e \\u0938\\u0915\\u0924\\u0947 \\u0939\\u0948\\u0902\\u0964 \\u0915\\u0947\\u092e\\u0947\\u0915\\u0948\\u0921\\u092e\\u0940 \\u0915\\u0947 \\