(92, 8, 'vi', '{\"title\":\"M\\u1ecdi ng\\u01b0\\u1eddi \\u0111\\u1ec1u c\\u00f3 m\\u1ed9t c\\u00e1i g\\u00ec \\u0111\\u00f3 \\u0111\\u1ec3 d\\u1ea1y. M\\u1ecdi ng\\u01b0\\u1eddi \\u0111\\u1ec1u c\\u1ea7n m\\u1ed9t c\\u00e1i g\\u00ec \\u0111\\u00f3 \\u0111\\u1ec3 h\\u1ecdc\",\"description\":\"Nhi\\u1ec7m v\\u1ee5 c\\u1ee7a ch\\u00fang t\\u00f4i t\\u1ea1i Kemecademy l\\u00e0 n\\u00e2ng cao tr\\u00ecnh \\u0111\\u1ed9 k\\u1ef9 thu\\u1eadt v\\u00e0 chuy\\u00ean m\\u00f4n c\\u1ee7a t\\u1ea5t c\\u1ea3 nh\\u1eefng ng\\u01b0\\u1eddi l\\u00e0m vi\\u1ec7c trong ng\\u00e0nh b\\u1ea5t \\u0111\\u1ed9ng s\\u1ea3n, t\\u1eeb th\\u1ee3 th\\u1ee7 c\\u00f4ng v\\u00e0 k\\u1ef9 thu\\u1eadt vi\\u00ean \\u0111\\u1ebfn nh\\u00e0 ti\\u1ebfp th\\u1ecb v\\u00e0 d\\u1ecbch gi\\u1ea3 t\\u1ef1 do. C\\u00e1c \\u0111\\u1ea1i l\\u00fd v\\u00e0 nh\\u00e0 \\u0111\\u1ea7u t\\u01b0 b\\u1ea5t \\u0111\\u1ed9ng s\\u1ea3n c\\u0169ng c\\u00f3 th\\u1ec3 t\\u1eadn d\\u1ee5ng c\\u00e1c ch\\u01b0\\u01a1ng tr\\u00ecnh chuy\\u00ean bi\\u1ec7t. C\\u00e1c gi\\u1ea3ng vi\\u00ean c\\u1ee7a Kemecademy \\u0111\\u1ec1u l\\u00e0 nh\\u1eefng chuy\\u00ean gia c\\u00f3 kinh nghi\\u1ec7m tuy\\u1ec7t v\\u1eddi, nh\\u1eefng ng\\u01b0\\u1eddi th\\u00edch chia s\\u1ebb kinh nghi\\u1ec7m c\\u1ee7a h\\u1ecd v\\u1edbi ng\\u01b0\\u1eddi kh\\u00e1c. Nhi\\u1ec1u kh\\u00f3a h\\u1ecdc c\\u1ee7a h\\u1ecd l\\u00e0 mi\\u1ec5n ph\\u00ed. Thanh ni\\u00ean v\\u00e0 tr\\u1ebb em c\\u00f3 th\\u1ec3 h\\u01b0\\u1edfng l\\u1ee3i t\\u1eeb c\\u00e1c ch\\u01b0\\u01a1ng tr\\u00ecnh \\u0111\\u00e0o t\\u1ea1o chuy\\u00ean bi\\u1ec7t\",\"hero_background\":\"\\/store\\/1\\/general images\\/hero.jpg\",\"is_video_background\":\"0\"}'),
