(107, 27, 'vi', '{\"link\":null,\"title\":\"Tr\\u1edf th\\u00e0nh chuy\\u00ean gia trong m\\u1ed9t ngh\\u1ec1 th\\u1ee7 c\\u00f4ng\",\"description\":\"Trong h\\u1ecdc vi\\u1ec7n c\\u1ee7a ch\\u00fang t\\u00f4i, c\\u00e1c chuy\\u00ean gia chia s\\u1ebb nh\\u1eefng b\\u00ed m\\u1eadt trong ngh\\u1ec1 c\\u1ee7a h\\u1ecd v\\u1edbi h\\u1ecdc sinh c\\u1ee7a h\\u1ecd.\",\"background\":\"\\/store\\/1\\/general images\\/video-section.jpg\"}'),
(108, 32, 'bn', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"\\u09b8\\u09c7\\u09b0\\u09be \\u09aa\\u09cd\\u09b0\\u09b6\\u09bf\\u0995\\u09cd\\u09b7\\u0995, \\u09aa\\u09b0\\u09be\\u09ae\\u09b0\\u09cd\\u09b6\\u09a6\\u09be\\u09a4\\u09be \\u09ac\\u09be \\u0997\\u09c3\\u09b9\\u09b6\\u09bf\\u0995\\u09cd\\u09b7\\u0995 \\u0996\\u09c1\\u0981\\u099c\\u09c1\\u09a8\",\"description\":\"\\u098f\\u0995\\u099c\\u09a8 \\u09aa\\u09cd\\u09b0\\u09b6\\u09bf\\u0995\\u09cd\\u09b7\\u0995, \\u09aa\\u09b0\\u09be\\u09ae\\u09b0\\u09cd\\u09b6\\u09a6\\u09be\\u09a4\\u09be \\u09ac\\u09be \\u0997\\u09c3\\u09b9\\u09b6\\u09bf\\u0995\\u09cd\\u09b7\\u0995 \\u0996\\u09c1\\u0981\\u099c\\u099b\\u09c7\\u09a8? \\u09b2\\u09bf\\u0999\\u09cd\\u0997, \\u09a6\\u0995\\u09cd\\u09b7\\u09a4\\u09be\\u09b0 \\u09b8\\u09cd\\u09a4\\u09b0, \\u09ae\\u09c2\\u09b2\\u09cd\\u09af, \\u09ae\\u09bf\\u099f\\u09bf\\u0982\\u09af\\u09bc\\u09c7\\u09b0 \\u09a7\\u09b0\\u09a8, \\u09b0\\u09c7\\u099f\\u09bf\\u0982 \\u0987\\u09a4\\u09cd\\u09af\\u09be\\u09a6\\u09bf\\u09b0 \\u09ae\\u09a4\\u09cb \\u09ac\\u09bf\\u09ad\\u09bf\\u09a8\\u09cd\\u09a8 \\u09aa\\u09b0\\u09be\\u09ae\\u09bf\\u09a4\\u09bf \\u0985\\u09a8\\u09c1\\u09b8\\u09be\\u09b0\\u09c7 \\u09b8\\u09c7\\u09b0\\u09be\\u099f\\u09bf \\u09b8\\u09a8\\u09cd\\u09a7\\u09be\\u09a8 \\u0995\\u09b0\\u09c1\\u09a8\\u0964\",\"button1\":{\"title\":\"\\u0985\\u09a8\\u09c1\\u09b8\\u09a8\\u09cd\\u09a7\\u09be\\u09a8 \\u0989\\u0987\\u099c\\u09be\\u09b0\\u09cd\\u09a1\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"\\u09ae\\u09be\\u09a8\\u099a\\u09bf\\u09a4\\u09cd\\u09b0\\u09c7\",\"link\":\"\\/instructor-finder\"}}'),
(109, 32, 'zh', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"\\u627e\\u5230\\u6700\\u597d\\u7684\\u8bb2\\u5e08\\u3001\\u987e\\u95ee\\u6216\\u5bfc\\u5e08\",\"description\":\"\\u6b63\\u5728\\u5bfb\\u627e\\u8bb2\\u5e08\\u3001\\u987e\\u95ee\\u6216\\u5bfc\\u5e08\\uff1f \\u6839\\u636e\\u6027\\u522b\\u3001\\u6280\\u80fd\\u6c34\\u5e73\\u3001\\u4ef7\\u683c\\u3001\\u4f1a\\u8bae\\u7c7b\\u578b\\u3001\\u8bc4\\u7ea7\\u7b49\\u4e0d\\u540c\\u53c2\\u6570\\u627e\\u5230\\u6700\\u4f73\\u9009\\u62e9\\u3002\",\"button1\":{\"title\":\"\\u641c\\u7d22\\u7cbe\\u7075\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"\\u5728\\u5730\\u56fe\\u4e0a\",\"link\":\"\\/instructor-finder\"}}'),
(110, 32, 'fr', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"Trouvez le meilleur instructeur, consultant ou tuteur\",\"description\":\"Vous cherchez un instructeur, un consultant ou un tuteur? Trouvez le meilleur en fonction de diff\\u00e9rents param\\u00e8tres tels que le sexe, le niveau de comp\\u00e9tence, le prix, le type de r\\u00e9union, la note, etc.\",\"button1\":{\"title\":\"Assistant de recherche\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"Sur la carte\",\"link\":\"\\/instructor-finder\"}}'),
(111, 32, 'de', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"Finden Sie den besten Ausbilder, Berater oder Tutor\",\"description\":\"Sie suchen einen Ausbilder, Berater oder Tutor? Finden Sie die beste nach verschiedenen Parametern wie Geschlecht, Qualifikationsniveau, Preis, Meeting-Typ, Bewertung usw.\",\"button1\":{\"title\":\"Suchassistent\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"Auf Karte\",\"link\":\"\\/instructor-finder\"}}'),
(112, 32, 'hi', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"\\u0938\\u0930\\u094d\\u0935\\u0936\\u094d\\u0930\\u0947\\u0937\\u094d\\u0920 \\u092a\\u094d\\u0930\\u0936\\u093f\\u0915\\u094d\\u0937\\u0915, \\u0938\\u0932\\u093e\\u0939\\u0915\\u093e\\u0930 \\u092f\\u093e \\u0936\\u093f\\u0915\\u094d\\u0937\\u0915 \\u0916\\u094b\\u091c\\u0947\\u0902\",\"description\":\"\\u092a\\u094d\\u0930\\u0936\\u093f\\u0915\\u094d\\u0937\\u0915, \\u0938\\u0932\\u093e\\u0939\\u0915\\u093e\\u0930 \\u092f\\u093e \\u0936\\u093f\\u0915\\u094d\\u0937\\u0915 \\u0915\\u0940 \\u0924\\u0932\\u093e\\u0936 \\u0939\\u0948? \\u0932\\u093f\\u0902\\u0917, \\u0915\\u094c\\u0936\\u0932 \\u0938\\u094d\\u0924\\u0930, \\u092e\\u0942\\u0932\\u094d\\u092f, \\u092c\\u0948\\u0920\\u0915 \\u092a\\u094d\\u0930\\u0915\\u093e\\u0930, \\u0930\\u0947\\u091f\\u093f\\u0902\\u0917 \\u0906\\u0926\\u093f \\u091c\\u0948\\u0938\\u0947 \\u0935\\u093f\\u092d\\u093f\\u0928\\u094d\\u0928 \\u092e\\u093e\\u092a\\u0926\\u0902\\u0921\\u094b\\u0902 \\u0915\\u0947 \\u0905\\u0928\\u0941\\u0938\\u093e\\u0930 \\u0938\\u0930\\u094d\\u0935\\u0936\\u094d\\u0930\\u0947\\u0937\\u094d\\u0920 \\u0915\\u093e \\u092a\\u0924\\u093e \\u0932\\u0917\\u093e\\u090f\\u0902\\u0964\",\"button1\":{\"title\":\"\\u0916\\u094b\\u091c \\u0935\\u093f\\u091c\\u093c\\u093e\\u0930\\u094d\\u0921\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"\\u092e\\u093e\\u0928\\u091a\\u093f\\u0924\\u094d\\u0930 \\u092a\\u0930\",\"link\":\"\\/instructor-finder\"}}'),
(113, 32, 'id', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"Temukan instruktur, konsultan, atau tutor terbaik\",\"description\":\"Mencari instruktur, konsultan atau tutor? Temukan yang terbaik menurut parameter yang berbeda seperti jenis kelamin, tingkat keterampilan, harga, jenis pertemuan, peringkat, dll.\",\"button1\":{\"title\":\"Panduan Pencarian\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"Di Peta\",\"link\":\"\\/instructor-finder\"}}'),
(114, 32, 'it', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"Trova il miglior istruttore, consulente o tutor\",\"description\":\"Cerchi un istruttore, un consulente o un tutor? Trova il migliore in base a diversi parametri come sesso, livello di competenza, prezzo, tipo di incontro, valutazione, ecc.\",\"button1\":{\"title\":\"Ricerca guidata\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"Sulla mappa\",\"link\":\"\\/instructor-finder\"}}'),
(115, 32, 'ja', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"\\u6700\\u9ad8\\u306e\\u30a4\\u30f3\\u30b9\\u30c8\\u30e9\\u30af\\u30bf\\u30fc\\u3001\\u30b3\\u30f3\\u30b5\\u30eb\\u30bf\\u30f3\\u30c8\\u3001\\u30c1\\u30e5\\u30fc\\u30bf\\u30fc\\u3092\\u898b\\u3064\\u3051\\u308b\",\"description\":\"\\u30a4\\u30f3\\u30b9\\u30c8\\u30e9\\u30af\\u30bf\\u30fc\\u3001\\u30b3\\u30f3\\u30b5\\u30eb\\u30bf\\u30f3\\u30c8\\u3001\\u30c1\\u30e5\\u30fc\\u30bf\\u30fc\\u3092\\u304a\\u63a2\\u3057\\u3067\\u3059\\u304b\\uff1f \\u6027\\u5225\\u3001\\u30b9\\u30ad\\u30eb\\u30ec\\u30d9\\u30eb\\u3001\\u4fa1\\u683c\\u3001\\u4f1a\\u8b70\\u306e\\u7a2e\\u985e\\u3001\\u8a55\\u4fa1\\u306a\\u3069\\u306e\\u3055\\u307e\\u3056\\u307e\\u306a\\u30d1\\u30e9\\u30e1\\u30fc\\u30bf\\u30fc\\u306b\\u5f93\\u3063\\u3066\\u3001\\u6700\\u9069\\u306a\\u3082\\u306e\\u3092\\u898b\\u3064\\u3051\\u307e\\u3059\\u3002\",\"button1\":{\"title\":\"\\u691c\\u7d22\\u30a6\\u30a3\\u30b6\\u30fc\\u30c9\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"\\u5730\\u56f3\\u4e0a\",\"link\":\"\\/instructor-finder\"}}'),
(116, 32, 'ko', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"\\ucd5c\\uace0\\uc758 \\uac15\\uc0ac, \\ucee8\\uc124\\ud134\\ud2b8 \\ub610\\ub294 \\ud29c\\ud130 \\ucc3e\\uae30\",\"description\":\"\\uac15\\uc0ac, \\ucee8\\uc124\\ud134\\ud2b8 \\ub610\\ub294 \\ud29c\\ud130\\ub97c \\ucc3e\\uace0 \\uacc4\\uc2ed\\ub2c8\\uae4c? \\uc131\\ubcc4, \\uae30\\uc220 \\uc218\\uc900, \\uac00\\uaca9, \\ud68c\\uc758 \\uc720\\ud615, \\ub4f1\\uae09 \\ub4f1\\uacfc \\uac19\\uc740 \\ub2e4\\uc591\\ud55c \\ub9e4\\uac1c \\ubcc0\\uc218\\uc5d0 \\ub530\\ub77c \\ucd5c\\uc0c1\\uc758 \\uac83\\uc744 \\ucc3e\\uc73c\\uc2ed\\uc2dc\\uc624.\",\"button1\":{\"title\":\"\\uac80\\uc0c9 \\ub9c8\\ubc95\\uc0ac\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"\\uc9c0\\ub3c4\\uc5d0\\uc11c\",\"link\":\"\\/instructor-finder\"}}'),
(117, 32, 'ms', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"Cari pengajar, perunding atau tutor yang terbaik\",\"description\":\"Mencari pengajar, perunding atau tutor? Cari yang terbaik mengikut parameter berbeza seperti jantina, tahap kemahiran, harga, jenis mesyuarat, penilaian, dsb.\",\"button1\":{\"title\":\"Wizard Carian\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"Pada Peta\",\"link\":\"\\/instructor-finder\"}}'),
(118, 32, 'ru', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"\\u041d\\u0430\\u0439\\u0434\\u0438\\u0442\\u0435 \\u043b\\u0443\\u0447\\u0448\\u0435\\u0433\\u043e \\u0438\\u043d\\u0441\\u0442\\u0440\\u0443\\u043a\\u0442\\u043e\\u0440\\u0430, \\u043a\\u043e\\u043d\\u0441\\u0443\\u043b\\u044c\\u0442\\u0430\\u043d\\u0442\\u0430 \\u0438\\u043b\\u0438 \\u0440\\u0435\\u043f\\u0435\\u0442\\u0438\\u0442\\u043e\\u0440\\u0430\",\"description\":\"\\u0418\\u0449\\u0435\\u0442\\u0435 \\u0438\\u043d\\u0441\\u0442\\u0440\\u0443\\u043a\\u0442\\u043e\\u0440\\u0430, \\u043a\\u043e\\u043d\\u0441\\u0443\\u043b\\u044c\\u0442\\u0430\\u043d\\u0442\\u0430 \\u0438\\u043b\\u0438 \\u0440\\u0435\\u043f\\u0435\\u0442\\u0438\\u0442\\u043e\\u0440\\u0430? \\u041d\\u0430\\u0439\\u0434\\u0438\\u0442\\u0435 \\u043b\\u0443\\u0447\\u0448\\u0438\\u0439 \\u043f\\u043e \\u0440\\u0430\\u0437\\u043b\\u0438\\u0447\\u043d\\u044b\\u043c \\u043f\\u0430\\u0440\\u0430\\u043c\\u0435\\u0442\\u0440\\u0430\\u043c, \\u0442\\u0430\\u043a\\u0438\\u043c \\u043a\\u0430\\u043a \\u043f\\u043e\\u043b, \\u0443\\u0440\\u043e\\u0432\\u0435\\u043d\\u044c \\u043d\\u0430\\u0432\\u044b\\u043a\\u043e\\u0432, \\u0446\\u0435\\u043d\\u0430, \\u0442\\u0438\\u043f \\u0432\\u0441\\u0442\\u0440\\u0435\\u0447\\u0438, \\u0440\\u0435\\u0439\\u0442\\u0438\\u043d\\u0433 \\u0438 \\u0442. \\u0434.\",\"button1\":{\"title\":\"\\u041c\\u0430\\u0441\\u0442\\u0435\\u0440 \\u043f\\u043e\\u0438\\u0441\\u043a\\u0430\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"\\u041d\\u0430 \\u043a\\u0430\\u0440\\u0442\\u0435\",\"link\":\"\\/instructor-finder\"}}'),
(119, 32, 'th', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"\\u0e04\\u0e49\\u0e19\\u0e2b\\u0e32\\u0e1c\\u0e39\\u0e49\\u0e2a\\u0e2d\\u0e19 \\u0e17\\u0e35\\u0e48\\u0e1b\\u0e23\\u0e36\\u0e01\\u0e29\\u0e32 \\u0e2b\\u0e23\\u0e37\\u0e2d\\u0e15\\u0e34\\u0e27\\u0e40\\u0e15\\u0e2d\\u0e23\\u0e4c\\u0e17\\u0e35\\u0e48\\u0e14\\u0e35\\u0e17\\u0e35\\u0e48\\u0e2a\\u0e38\\u0e14\",\"description\":\"\\u0e01\\u0e33\\u0e25\\u0e31\\u0e07\\u0e21\\u0e2d\\u0e07\\u0e2b\\u0e32\\u0e1c\\u0e39\\u0e49\\u0e2a\\u0e2d\\u0e19 \\u0e17\\u0e35\\u0e48\\u0e1b\\u0e23\\u0e36\\u0e01\\u0e29\\u0e32 \\u0e2b\\u0e23\\u0e37\\u0e2d\\u0e15\\u0e34\\u0e27\\u0e40\\u0e15\\u0e2d\\u0e23\\u0e4c? \\u0e04\\u0e49\\u0e19\\u0e2b\\u0e32\\u0e2a\\u0e34\\u0e48\\u0e07\\u0e17\\u0e35\\u0e48\\u0e14\\u0e35\\u0e17\\u0e35\\u0e48\\u0e2a\\u0e38\\u0e14\\u0e15\\u0e32\\u0e21\\u0e1e\\u0e32\\u0e23\\u0e32\\u0e21\\u0e34\\u0e40\\u0e15\\u0e2d\\u0e23\\u0e4c\\u0e15\\u0e48\\u0e32\\u0e07\\u0e46 \\u0e40\\u0e0a\\u0e48\\u0e19 \\u0e40\\u0e1e\\u0e28 \\u0e23\\u0e30\\u0e14\\u0e31\\u0e1a\\u0e17\\u0e31\\u0e01\\u0e29\\u0e30 \\u0e23\\u0e32\\u0e04\\u0e32 \\u0e1b\\u0e23\\u0e30\\u0e40\\u0e20\\u0e17\\u0e01\\u0e32\\u0e23\\u0e1b\\u0e23\\u0e30\\u0e0a\\u0e38\\u0e21 \\u0e01\\u0e32\\u0e23\\u0e43\\u0e2b\\u0e49\\u0e04\\u0e30\\u0e41\\u0e19\\u0e19 \\u0e2f\\u0e25\\u0e2f\",\"button1\":{\"title\":\"\\u0e15\\u0e31\\u0e27\\u0e0a\\u0e48\\u0e27\\u0e22\\u0e2a\\u0e23\\u0e49\\u0e32\\u0e07\\u0e01\\u0e32\\u0e23\\u0e04\\u0e49\\u0e19\\u0e2b\\u0e32\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"\\u0e1a\\u0e19\\u0e41\\u0e1c\\u0e19\\u0e17\\u0e35\\u0e48\",\"link\":\"\\/instructor-finder\"}}'),
(120, 32, 'tr', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"En iyi e\\u011fitmeni, dan\\u0131\\u015fman\\u0131 veya \\u00f6\\u011fretmeni bulun\",\"description\":\"E\\u011fitmen, dan\\u0131\\u015fman veya \\u00f6\\u011fretmen mi ar\\u0131yorsunuz? Cinsiyet, beceri d\\u00fczeyi, fiyat, toplant\\u0131 t\\u00fcr\\u00fc, derecelendirme vb. farkl\\u0131 parametrelere g\\u00f6re en iyisini bulun.\",\"button1\":{\"title\":\"Arama Sihirbaz\\u0131\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"Haritada\",\"link\":\"\\/instructor-finder\"}}');
