(121, 32, 'ur', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"\\u0628\\u06c1\\u062a\\u0631\\u06cc\\u0646 \\u0627\\u0646\\u0633\\u0679\\u0631\\u06a9\\u0679\\u0631\\u060c \\u06a9\\u0646\\u0633\\u0644\\u0679\\u0646\\u0679 \\u06cc\\u0627 \\u0679\\u06cc\\u0648\\u0679\\u0631 \\u062a\\u0644\\u0627\\u0634 \\u06a9\\u0631\\u06cc\\u06ba\\u06d4\",\"description\":\"\\u0627\\u06cc\\u06a9 \\u0627\\u0646\\u0633\\u0679\\u0631\\u06a9\\u0679\\u0631\\u060c \\u06a9\\u0646\\u0633\\u0644\\u0679\\u0646\\u0679 \\u06cc\\u0627 \\u0679\\u06cc\\u0648\\u0679\\u0631 \\u06a9\\u06cc \\u062a\\u0644\\u0627\\u0634 \\u06c1\\u06d2\\u061f \\u0645\\u062e\\u062a\\u0644\\u0641 \\u067e\\u06cc\\u0631\\u0627\\u0645\\u06cc\\u0679\\u0631\\u0632 \\u062c\\u06cc\\u0633\\u06d2 \\u062c\\u0646\\u0633\\u060c \\u0645\\u06c1\\u0627\\u0631\\u062a \\u06a9\\u06cc \\u0633\\u0637\\u062d\\u060c \\u0642\\u06cc\\u0645\\u062a\\u060c \\u0645\\u0644\\u0627\\u0642\\u0627\\u062a \\u06a9\\u06cc \\u0642\\u0633\\u0645\\u060c \\u062f\\u0631\\u062c\\u06c1 \\u0628\\u0646\\u062f\\u06cc \\u0648\\u063a\\u06cc\\u0631\\u06c1 \\u06a9\\u06d2 \\u0645\\u0637\\u0627\\u0628\\u0642 \\u0628\\u06c1\\u062a\\u0631\\u06cc\\u0646 \\u062a\\u0644\\u0627\\u0634 \\u06a9\\u0631\\u06cc\\u06ba\\u06d4\",\"button1\":{\"title\":\"\\u0633\\u0631\\u0686 \\u0648\\u0632\\u0631\\u0688\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"\\u0646\\u0642\\u0634\\u06d2 \\u067e\\u0631\",\"link\":\"\\/instructor-finder\"}}'),
(122, 32, 'vi', '{\"image\":\"\\/store\\/1\\/general images\\/find-tutor.jpg\",\"title\":\"T\\u00ecm ng\\u01b0\\u1eddi h\\u01b0\\u1edbng d\\u1eabn, c\\u1ed1 v\\u1ea5n ho\\u1eb7c gia s\\u01b0 t\\u1ed1t nh\\u1ea5t\",\"description\":\"T\\u00ecm ki\\u1ebfm m\\u1ed9t ng\\u01b0\\u1eddi h\\u01b0\\u1edbng d\\u1eabn, t\\u01b0 v\\u1ea5n ho\\u1eb7c gia s\\u01b0? T\\u00ecm c\\u00e1i t\\u1ed1t nh\\u1ea5t theo c\\u00e1c th\\u00f4ng s\\u1ed1 kh\\u00e1c nhau nh\\u01b0 gi\\u1edbi t\\u00ednh, c\\u1ea5p \\u0111\\u1ed9 k\\u1ef9 n\\u0103ng, gi\\u00e1 c\\u1ea3, lo\\u1ea1i cu\\u1ed9c h\\u1ecdp, x\\u1ebfp h\\u1ea1ng, v.v.\",\"button1\":{\"title\":\"thu\\u1eadt s\\u0129 t\\u00ecm ki\\u1ebfm\",\"link\":\"\\/instructor-finder\\/wizard\"},\"button2\":{\"title\":\"tr\\u00ean b\\u1ea3n \\u0111\\u1ed3\",\"link\":\"\\/instructor-finder\"}}'),
