(125, 33, 'fr', '{\"image\":\"\\/store\\/1\\/general images\\/club-points.png\",\"title\":\"Gagnez des Kemecoins\",\"description\":\"Utilisez Kemecademy et gagnez des Kemecoins selon diff\\u00e9rentes activit\\u00e9s. Vous pourrez utiliser vos pi\\u00e8ces pour obtenir des prix et des cours gratuits. Commencez \\u00e0 utiliser le syst\\u00e8me maintenant et collectez des pi\\u00e8ces\\u00a0!\",\"button1\":{\"title\":\"R\\u00e9compenses\",\"link\":\"\\/reward-courses\"},\"button2\":{\"title\":\"Vos Kemecoins\",\"link\":\"\\/panel\\/rewards\"}}'),
(126, 33, 'de', '{\"image\":\"\\/store\\/1\\/general images\\/club-points.png\",\"title\":\"Kemecoins gewinnen\",\"description\":\"Verwenden Sie Kemecademy und gewinnen Sie Kemecoins bei verschiedenen Aktivit\\u00e4ten. Sie k\\u00f6nnen Ihre Coins verwenden, um kostenlose Preise und Kurse zu erhalten. Nutzen Sie das System jetzt und sammeln Sie Coins!\",\"button1\":{\"title\":\"Belohnung\",\"link\":\"\\/reward-courses\"},\"button2\":{\"title\":\"Ihre Kemecoins\",\"link\":\"\\/panel\\/rewards\"}}'),
