(128, 33, 'id', '{\"image\":\"\\/store\\/1\\/general images\\/club-points.png\",\"title\":\"Menangkan Kemecoin\",\"description\":\"Gunakan Kemecademy dan menangkan Kemecoin sesuai dengan aktivitas yang berbeda. Anda akan dapat menggunakan koin Anda untuk mendapatkan hadiah dan kursus gratis. Mulai gunakan sistem sekarang dan kumpulkan koin!\",\"button1\":{\"title\":\"Hadiah\",\"link\":\"\\/reward-courses\"},\"button2\":{\"title\":\"Kemecoin Anda\",\"link\":\"\\/panel\\/rewards\"}}'),
(129, 33, 'it', '{\"image\":\"\\/store\\/1\\/general images\\/club-points.png\",\"title\":\"Vinci Kemecoin\",\"description\":\"Usa Kemecademy e vinci Kemecoin in base alle diverse attivit\\u00e0. Potrai utilizzare le tue monete per ottenere premi e corsi gratuiti. Inizia subito a utilizzare il sistema e raccogli le monete!\",\"button1\":{\"title\":\"Premi\",\"link\":\"\\/reward-courses\"},\"button2\":{\"title\":\"I tuoi Kemecoin\",\"link\":\"\\/panel\\/rewards\"}}'),
