(137, 33, 'vi', '{\"image\":\"\\/store\\/1\\/general images\\/club-points.png\",\"title\":\"Ki\\u1ebfm \\u0111\\u01b0\\u1ee3c kemecoin\",\"description\":\"S\\u1eed d\\u1ee5ng Kemecademy v\\u00e0 gi\\u00e0nh \\u0111\\u01b0\\u1ee3c Kemecoin theo c\\u00e1c ho\\u1ea1t \\u0111\\u1ed9ng kh\\u00e1c nhau. B\\u1ea1n s\\u1ebd c\\u00f3 th\\u1ec3 s\\u1eed d\\u1ee5ng ti\\u1ec1n c\\u1ee7a m\\u00ecnh \\u0111\\u1ec3 nh\\u1eadn c\\u00e1c gi\\u1ea3i th\\u01b0\\u1edfng v\\u00e0 kh\\u00f3a h\\u1ecdc mi\\u1ec5n ph\\u00ed. B\\u1eaft \\u0111\\u1ea7u s\\u1eed d\\u1ee5ng h\\u1ec7 th\\u1ed1ng ngay b\\u00e2y gi\\u1edd v\\u00e0 thu th\\u1eadp ti\\u1ec1n xu!\",\"button1\":{\"title\":\"Ph\\u1ea7n th\\u01b0\\u1edfng\",\"link\":\"\\/reward-courses\"},\"button2\":{\"title\":\"Kemecoin c\\u1ee7a b\\u1ea1n\",\"link\":\"\\/panel\\/rewards\"}}'),
