\u092e\\u093e\\u092a \\u0938\\u0915\\u0947\\u0902 \\u0914\\u0930 \\u0938\\u0941\\u0927\\u093e\\u0930 \\u0938\\u0915\\u0947\\u0902\\u0964 \\u0935\\u0947 \\u0939\\u092e\\u0947\\u0902 \\u092f\\u0939 \\u091c\\u093e\\u0928\\u0928\\u0947 \\u092e\\u0947\\u0902 \\u092e\\u0926\\u0926 \\u0915\\u0930\\u0924\\u0947 \\u0939\\u0948\\u0902 \\u0915\\u093f \\u0915\\u094c\\u0928 \\u0938\\u0947 \\u092a\\u0943\\u0937\\u094d\\u0920 \\u0938\\u092c\\u0938\\u0947 \\u0905\\u0927\\u093f\\u0915 \\u0914\\u0930 \\u0938\\u092c\\u0938\\u0947 \\u0915\\u092e \\u0932\\u094b\\u0915\\u092a\\u094d\\u0930\\u093f\\u092f \\u0939\\u0948\\u0902 \\u0914\\u0930 \\u0926\\u0947\\u0916\\u0924\\u0947 \\u0939\\u0948\\u0902 \\u0915\\u093f \\u0935\\u093f\\u091c\\u093c\\u093f\\u091f\\u0930 \\u0938\\u093e\\u0907\\u091f \\u092a\\u0930 \\u0915\\u0948\\u0938\\u0947 \\u0918\\u0942\\u092e\\u0924\\u0947 \\u0939\\u0948\\u0902, \\u091c\\u093f\\u0938\\u0938\\u0947 \\u0939\\u092e\\u0947\\u0902 \\u0906\\u092a\\u0915\\u0947 \\u0905\\u0928\\u0941\\u092d\\u0935 \\u0915\\u094b \\u0905\\u0928\\u0941\\u0915\\u0942\\u0932\\u093f\\u0924 \\u0915\\u0930\\u0928\\u0947 \\u092e\\u0947\\u0902 \\u092e\\u0926\\u0926 \\u092e\\u093f\\u0932\\u0924\\u0940 \\u0939\\u0948\\u0964 \\u0907\\u0928 \\u0915\\u0941\\u0915\\u0940\\u091c\\u093c \\u0926\\u094d\\u0935\\u093e\\u0930\\u093e \\u090f\\u0915\\u0924\\u094d\\u0930 \\u0915\\u0940 \\u091c\\u093e\\u0928\\u0947 \\u0935\\u093e\\u0932\\u0940 \\u0938\\u092d\\u0940 \\u091c\\u093e\\u0928\\u0915\\u093e\\u0930\\u0940 \\u090f\\u0915\\u0924\\u094d\\u0930\\u093f\\u0924 \\u0939\\u094b\\u0924\\u0940 \\u0939\\u0948 \\u0914\\u0930 \\u0907\\u0938\\u0932\\u093f\\u090f \\u0905\\u0928\\u093e\\u092e \\u0939\\u094b\\u0924\\u0940 \\u0939\\u0948\\u0964 \\u092f\\u0926\\u093f \\u0906\\u092a \\u0907\\u0928 \\u0915\\u0941\\u0915\\u0940\\u091c\\u093c \\u0915\\u0940 \\u0905\\u0928\\u0941\\u092e\\u0924\\u093f \\u0928\\u0939\\u0940\\u0902 \\u0926\\u0947\\u0924\\u0947 \\u0939\\u0948\\u0902 \\u0924\\u094b \\u0939\\u092e \\u0907\\u0938 \\u0924\\u0930\\u0939 \\u0938\\u0947 \\u0906\\u092a\\u0915\\u0947 \\u0921\\u0947\\u091f\\u093e \\u0915\\u093e \\u0909\\u092a\\u092f\\u094b\\u0917 \\u0928\\u0939\\u0940\\u0902 \\u0915\\u0930 \\u092a\\u093e\\u090f\\u0902\\u0917\\u0947\\u0964\",\"required\":\"0\"},\"GHLwdXfKvLtgCnyJ\":{\"title\":\"\\u0938\\u0916\\u094d\\u0924 \\u091c\\u0930\\u0942\\u0930\\u0940 \\u0939\\u0948\",\"description\":\"\\u092f\\u0947 \\u0915\\u0941\\u0915\\u0940\\u091c\\u093c \\u0939\\u092e\\u093e\\u0930\\u0940 \\u0935\\u0947\\u092c\\u0938\\u093e\\u0907\\u091f \\u0915\\u0947 \\u0920\\u0940\\u0915 \\u0938\\u0947 \\u0915\\u093e\\u092e \\u0915\\u0930\\u0928\\u0947 \\u0915\\u0947 \\u0932\\u093f\\u090f \\u0906\\u0935\\u0936\\u094d\\u092f\\u0915 \\u0939\\u0948\\u0902 \\u0914\\u0930 \\u0907\\u0928\\u094d\\u0939\\u0947\\u0902 \\u0939\\u092e\\u093e\\u0930\\u0947 \\u0938\\u093f\\u0938\\u094d\\u091f\\u092e \\u092e\\u0947\\u0902 \\u092c\\u0902\\u0926 \\u0928\\u0939\\u0940\\u0902 \\u0915\\u093f\\u092f\\u093e \\u091c\\u093e \\u0938\\u0915\\u0924\\u093e \\u0939\\u0948\\u0964 \\u0935\\u0947 \\u0906\\u092e\\u0924\\u094c\\u0930 \\u092a\\u0930 \\u0915\\u0947\\u0935\\u0932 \\u0906\\u092a\\u0915\\u0947 \\u0926\\u094d\\u0935\\u093e\\u0930\\u093e \\u0915\\u0940 \\u0917\\u0908 \\u0915\\u093e\\u0930\\u094d\\u0930\\u0935\\u093e\\u0907\\u092f\\u094b\\u0902 \\u0915\\u0947 \\u091c\\u0935\\u093e\\u092c \\u092e\\u0947\\u0902 \\u0938\\u0947\\u091f \\u0915\\u093f\\u090f \\u091c\\u093e\\u0924\\u0947 \\u0939\\u0948\\u0902 \\u091c\\u094b \\u0938\\u0947\\u0935\\u093e\\u0913\\u0902 \\u0915\\u0947 \\u0932\\u093f\\u090f \\u0905\\u0928\\u0941\\u0930\\u094b\\u0927 \\u0915\\u0947 \\u092c\\u0930\\u093e\\u092c\\u0930 \\u0939\\u094b\\u0924\\u0947 \\u0939\\u0948\\u0902, \\u091c\\u0948\\u0938\\u0947 \\u0915\\u093f \\u0906\\u092a\\u0915\\u0940 \\u0917\\u094b\\u092a\\u0928\\u0940\\u092f\\u0924\\u093e \\u092a\\u094d\\u0930\\u093e\\u0925\\u092e\\u093f\\u0915\\u0924\\u093e\\u090f\\u0902 \\u0938\\u0947\\u091f \\u0915\\u0930\\u0928\\u093e, \\u0932\\u0949\\u0917 \\u0907\\u0928 \\u0915\\u0930\\u0928\\u093e \\u092f\\u093e \\u092b\\u0949\\u0930\\u094d\\u092e \\u092d\\u0930\\u0928\\u093e, \\u092f\\u093e \\u091c\\u0939\\u093e\\u0902 \\u0935\\u0947 \\u0906\\u092a\\u0915\\u0947 \\u0926\\u094d\\u0935\\u093e\\u0930\\u093e \\u0905\\u0928\\u0941\\u0930\\u094b\\u0927\\u093f\\u0924 \\u0938\\u0947\\u0935\\u093e \\u092a\\u094d\\u0930\\u0926\\u093e\\u0928 \\u0915\\u0930\\u0928\\u0947 \\u0915\\u0947 \\u0932\\u093f\\u090f \\u0906\\u0935\\u0936\\u094d\\u092f\\u0915 \\u0939\\u0948\\u0902\\u0964 \\u0906\\u092a \\u0907\\u0928 \\u0915\\u0941\\u0915\\u0940\\u091c\\u093c \\u0938\\u0947 \\u0911\\u092a\\u094d\\u091f \\u0906\\u0909\\u091f \\u0928\\u0939\\u0940\\u0902 \\u0915\\u0930 \\u0938\\u0915\\u0924\\u0947 \\u0939\\u0948\\u0902\\u0964 \\u0906\\u092a \\u0905\\u092a\\u0928\\u0947 \\u092c\\u094d\\u0930\\u093e\\u0909\\u091c\\u093c\\u0930 \\u0915\\u094b \\u0907\\u0928 \\u0915\\u0941\\u0915\\u0940\\u091c\\u093c \\u0915\\u0947 \\u092c\\u093e\\u0930\\u0947 \\u092e\\u0947\\u0902 \\u092c\\u094d\\u0932\\u0949\\u0915 \\u092f\\u093e \\u0905\\u0932\\u0930\\u094d\\u091f \\u0915\\u0930\\u0928\\u0947 \\u0915\\u0947 \\u0932\\u093f\\u090f \\u0938\\u0947\\u091f \\u0915\\u0930 \\u0938\\u0915\\u0924\\u0947 \\u0939\\u0948\\u0902, \\u0932\\u0947\\u0915\\u093f\\u0928 \\u092f\\u0926\\u093f \\u0906\\u092a \\u0910\\u0938\\u093e \\u0915\\u0930\\u0924\\u0947 \\u0939\\u0948\\u0902, \\u0924\\u094b \\u0938\\u093e\\u0907\\u091f \\u0915\\u0947 \\u0915\\u0941\\u091b \\u0939\\u093f\\u0938\\u094d\\u0938\\u0947 \\u0924\\u092c \\u0915\\u093e\\u092e \\u0928\\u0939\\u0940\\u0902 \\u0915\\u0930\\u0947\\u0902\\u0917\\u0947\\u0964 \\u092f\\u0947 \\u0915\\u0941\\u0915\\u0940\\u091c\\u093c \\u0915\\u093f\\u0938\\u0940 \\u0935\\u094d\\u092f\\u0915\\u094d\\u0924\\u093f\\u0917\\u0924 \\u0930\\u0942\\u092a \\u0938\\u0947 \\u092a\\u0939\\u091a\\u093e\\u0928 \\u092f\\u094b\\u0917\\u094d\\u092f \\u091c\\u093e\\u0928\\u0915\\u093e\\u0930\\u0940 \\u0915\\u094b \\u0938\\u0902\\u0917\\u094d\\u0930\\u0939\\u0940\\u0924 \\u0928\\u0939\\u0940\\u0902 \\u0915\\u0930\\u0924\\u0940 \\u0939\\u0948\\u0902\\u0964\",\"required\":\"0\"}}}'),
(176, 44, 'id', '{\"cookie_settings_modal_message\":\"<p>Saat Anda mengunjungi salah satu situs web kami, situs web tersebut dapat menyimpan atau mengambil informasi di browser Anda, sebagian besar dalam bentuk cookie. Informasi ini mungkin tentang Anda, preferensi Anda, atau perangkat Anda dan sebagian besar digunakan untuk membuat situs berfungsi seperti yang Anda harapkan. Informasi tersebut biasanya tidak mengidentifikasi Anda secara langsung, tetapi dapat memberi Anda pengalaman web yang lebih dipersonalisasi. Karena kami menghormati hak privasi Anda, Anda dapat memilih untuk tidak mengizinkan beberapa jenis cookie. Klik judul kategori yang berbeda untuk mengetahui lebih lanjut dan mengelola preferensi Anda. Harap diperhatikan, bahwa memblokir beberapa jenis cookie dapat memengaruhi pengalaman Anda di situs dan layanan yang dapat kami tawarkan.<\\/p>\",\"cookie_settings_modal_items\":{\"DInQCnKhDTNIgPlo\":{\"title\":\"Menargetkan Cookie\",\"description\":\"Cookie ini dapat diatur melalui situs kami oleh mitra periklanan kami. Mereka dapat digunakan oleh perusahaan tersebut untuk membangun profil minat Anda dan menampilkan iklan yang relevan di situs lain. Mereka tidak menyimpan informasi pribadi secara langsung tetapi didasarkan pada pengidentifikasian browser dan perangkat internet Anda secara unik. Jika Anda tidak mengizinkan cookie ini, Anda akan mengalami iklan yang kurang bertarget.\",\"required\":\"0\"},\"LXucwINYkbPpHULD\":{\"title\":\"Cookie Fungsional\",\"description\":\"Cookie ini memungkinkan situs web menyediakan fungsionalitas dan personalisasi yang ditingkatkan. Mereka mungkin diatur oleh kami atau oleh penyedia pihak ketiga yang layanannya telah kami tambahkan ke halaman kami. Jika Anda tidak mengizinkan cookie ini, beberapa atau semua layanan ini mungkin tidak berfungsi dengan baik.\",\"required\":\"0\"},\"uIuaquIUTYPLJeRs\":{\"title\":\"Cookie Kinerja\",\"description\":\"Cookie ini memungkinkan kami menghitung kunjungan dan sumber lalu lintas sehingga kami dapat mengukur dan meningkatkan kinerja situs kami. Mereka membantu kami mengetahui halaman mana yang paling dan paling tidak populer dan melihat bagaimana pengunjung bergerak di sekitar situs, yang membantu kami mengoptimalkan pengalaman Anda. Semua informasi yang dikumpulkan cookie ini dikumpulkan dan karenanya anonim. Jika Anda tidak mengizinkan cookie ini, kami tidak akan dapat menggunakan data Anda dengan cara ini.\",\"required\":\"0\"},\"ocsZPgfzIJbHWozn\":{\"title\":\"Sangat Diperlukan\",\"description\":\"Cookie ini diperlukan agar situs web kami berfungsi dengan baik dan tidak dapat dimatikan di sistem kami. Mereka biasanya hanya diatur sebagai tanggapan atas tindakan yang Anda lakukan yang setara dengan permintaan layanan, seperti mengatur preferensi privasi Anda, masuk atau mengisi formulir, atau jika penting untuk menyediakan layanan yang Anda minta. Anda tidak dapat memilih keluar dari cookie ini. Anda dapat mengatur browser Anda untuk memblokir atau memberi tahu Anda tentang cookie ini, tetapi jika Anda melakukannya, beberapa bagian situs tidak akan berfungsi. Cookie ini tidak menyimpan informasi pengenal pribadi apa pun.\",\"required\":\"0\"}}}'),
(177, 44, 'it', '{\"cookie_settings_modal_message\":\"<p>Quando visiti uno qualsiasi dei nostri siti Web, \\u00e8 possibile che vengano archiviate o recuperate informazioni sul tuo browser, principalmente sotto forma di cookie. Queste informazioni potrebbero riguardare te, le tue preferenze o il tuo dispositivo e sono principalmente utilizzate per far funzionare il sito come ti aspetti. Le informazioni di solito non ti identificano direttamente, ma possono offrirti un\'esperienza web pi\\u00f9 personalizzata. Poich\\u00e9 rispettiamo il tuo diritto alla privacy, puoi scegliere di non consentire alcuni tipi di cookie. Clicca sulle intestazioni delle diverse categorie per saperne di pi\\u00f9 e gestire le tue preferenze. Tieni presente che il blocco di alcuni tipi di cookie pu\\u00f2 influire sulla tua esperienza del sito e sui servizi che siamo in grado di offrire.<\\/p>\",\"cookie_settings_modal_items\":{\"APCgMkXIbenyqtWS\":{\"title\":\"Cookie di targeting\",\"description\":\"Questi cookie possono essere impostati attraverso il nostro sito dai nostri partner pubblicitari. Possono essere utilizzati da tali societ\\u00e0 per creare un profilo dei tuoi interessi e mostrarti pubblicit\\u00e0 pertinenti su altri siti. Non memorizzano direttamente informazioni personali ma si basano sull\'identificazione univoca del browser e del dispositivo Internet. Se non autorizzi questi cookie, riceverai pubblicit\\u00e0 meno mirate.\",\"required\":\"0\"},\"vyydzFsvYTOkeyoR\":{\"title\":\"Cookie Funzionali\",\"description\":\"Questi cookie consentono al sito Web di fornire funzionalit\\u00e0 e personalizzazione avanzate. Possono essere impostati da noi o da fornitori di terze parti i cui servizi abbiamo aggiunto alle nostre pagine. Se non consenti questi cookie, alcuni o tutti questi servizi potrebbero non funzionare correttamente.\",\"required\":\"0\"},\"lQhhhKegpUjaFWzG\":{\"title\":\"Cookie sulle prestazioni\",\"description\":\"Questi cookie ci consentono di contare le visite e le fonti di traffico in modo da poter misurare e migliorare le prestazioni del nostro sito. Ci aiutano a sapere quali sono le pagine pi\\u00f9 e meno popolari e vedere come i visitatori si muovono nel sito, il che ci aiuta a ottimizzare la tua esperienza. Tutte le informazioni raccolte da questi cookie sono aggregate e quindi anonime. Se non autorizzi questi cookie non saremo in grado di utilizzare i tuoi dati in questo modo.\",\"required\":\"0\"},\"ysPQmAjYVPjPaaNv\":{\"title\":\"Strettamente necessario\",\"description\":\"Questi cookie sono necessari per il corretto funzionamento del nostro sito Web e non possono essere disattivati nei nostri sistemi. Di solito vengono impostati solo in risposta ad azioni da te effettuate che equivalgono a una richiesta di servizi, come l\'impostazione delle tue preferenze sulla privacy, l\'accesso o la compilazione di moduli, o laddove sono essenziali per fornirti un servizio che hai richiesto. Non puoi disattivare questi cookie. Puoi impostare il tuo browser per bloccare o avvisarti di questi cookie, ma se lo fai, alcune parti del sito non funzioneranno. Questi cookie non memorizzano alcuna informazione di identificazione personale.\",\"required\":\"0\"}}}'),
(178, 44, 'ja', '{\"cookie_settings_modal_message\":\"<p>\\u5f53\\u793e\\u306e Web \\u30b5\\u30a4\\u30c8\\u306b\\u30a2\\u30af\\u30bb\\u30b9\\u3059\\u308b\\u3068\\u3001\\u307b\\u3068\\u3093\\u3069\\u306e\\u5834\\u5408 Cookie \\u306e\\u5f62\\u5f0f\\u3067\\u3001\\u30d6\\u30e9\\u30a6\\u30b6\\u30fc\\u306b\\u60c5\\u5831\\u304c\\u4fdd\\u5b58\\u307e\\u305f\\u306f\\u53d6\\u5f97\\u3055\\u308c\\u308b\\u5834\\u5408\\u304c\\u3042\\u308a\\u307e\\u3059\\u3002 \\u3053\\u306e\\u60c5\\u5831\\u306f\\u3001\\u3042\\u306a\\u305f\\u3001\\u3042\\u306a\\u305f\\u306e\\u597d\\u307f\\u3001\\u307e\\u305f\\u306f\\u30c7\\u30d0\\u30a4\\u30b9\\u306b\\u95a2\\u3059\\u308b\\u3082\\u306e\\u3067\\u3042\\u308b\\u53ef\\u80fd\\u6027\\u304c\\u3042\\u308a\\u3001\\u4e3b\\u306b\\u30b5\\u30a4\\u30c8\\u3092\\u671f\\u5f85\\u3069\\u304a\\u308a\\u306b\\u6a5f\\u80fd\\u3055\\u305b\\u308b\\u305f\\u3081\\u306b\\u4f7f\\u7528\\u3055\\u308c\\u307e\\u3059. \\u3053\\u306e\\u60c5\\u5831\\u306f\\u901a\\u5e38\\u3001\\u3042\\u306a\\u305f\\u3092\\u76f4\\u63a5\\u7279\\u5b9a\\u3059\\u308b\\u3082\\u306e\\u3067\\u306f\\u3042\\u308a\\u307e\\u305b\\u3093\\u304c\\u3001\\u3088\\u308a\\u30d1\\u30fc\\u30bd\\u30ca\\u30e9\\u30a4\\u30ba\\u3055\\u308c\\u305f Web \\u30a8\\u30af\\u30b9\\u30da\\u30ea\\u30a8\\u30f3\\u30b9\\u3092\\u63d0\\u4f9b\\u3059\\u308b\\u3053\\u3068\\u304c\\u3067\\u304d\\u307e\\u3059\\u3002 \\u5f53\\u793e\\u306f\\u304a\\u5ba2\\u69d8\\u306e\\u30d7\\u30e9\\u30a4\\u30d0\\u30b7\\u30fc\\u306e\\u6a29\\u5229\\u3092\\u5c0a\\u91cd\\u3059\\u308b\\u305f\\u3081\\u3001\\u4e00\\u90e8\\u306e\\u7a2e\\u985e\\u306e Cookie \\u3092\\u8a31\\u53ef\\u3057\\u306a\\u3044\\u3053\\u3068\\u3092\\u9078\\u629e\\u3067\\u304d\\u307e\\u3059\\u3002 \\u3055\\u307e\\u3056\\u307e\\u306a\\u30ab\\u30c6\\u30b4\\u30ea\\u306e\\u898b\\u51fa\\u3057\\u3092\\u30af\\u30ea\\u30c3\\u30af\\u3057\\u3066\\u3001\\u8a73\\u7d30\\u3092\\u78ba\\u8a8d\\u3057\\u3001\\u8a2d\\u5b9a\\u3092\\u7ba1\\u7406\\u3057\\u307e\\u3059\\u3002 \\u4e00\\u90e8\\u306e\\u7a2e\\u985e\\u306e Cookie \\u3092\\u30d6\\u30ed\\u30c3\\u30af\\u3059\\u308b\\u3068\\u3001\\u30b5\\u30a4\\u30c8\\u306e\\u30a8\\u30af\\u30b9\\u30da\\u30ea\\u30a8\\u30f3\\u30b9\\u3084\\u5f53\\u793e\\u304c\\u63d0\\u4f9b\\u3067\\u304d\\u308b\\u30b5\\u30fc\\u30d3\\u30b9\\u306b\\u5f71\\u97ff\\u3092\\u4e0e\\u3048\\u308b\\u53ef\\u80fd\\u6027\\u304c\\u3042\\u308b\\u3053\\u3068\\u306b\\u6ce8\\u610f\\u3057\\u3066\\u304f\\u3060\\u3055\\u3044\\u3002<\\/p>\",\"cookie_settings_modal_items\":{\"rTYpqMHWVKWXowBy\":{\"title\":\"\\u30bf\\u30fc\\u30b2\\u30c6\\u30a3\\u30f3\\u30b0 Cookie\",\"description\":\"\\u3053\\u308c\\u3089\\u306e Cookie \\u306f\\u3001\\u5f53\\u793e\\u306e\\u5e83\\u544a\\u30d1\\u30fc\\u30c8\\u30ca\\u30fc\\u306b\\u3088\\u3063\\u3066\\u5f53\\u793e\\u306e\\u30b5\\u30a4\\u30c8\\u3092\\u901a\\u3058\\u3066\\u8a2d\\u5b9a\\u3055\\u308c\\u308b\\u5834\\u5408\\u304c\\u3042\\u308a\\u307e\\u3059\\u3002 \\u3053\\u308c\\u3089\\u306e\\u4f01\\u696d\\u306f\\u3001\\u304a\\u5ba2\\u69d8\\u306e\\u8208\\u5473\\u306e\\u30d7\\u30ed\\u30d5\\u30a1\\u30a4\\u30eb\\u3092\\u4f5c\\u6210\\u3057\\u3001\\u95a2\\u9023\\u3059\\u308b\\u5e83\\u544a\\u3092\\u4ed6\\u306e\\u30b5\\u30a4\\u30c8\\u306b\\u8868\\u793a\\u3059\\u308b\\u305f\\u3081\\u306b\\u4f7f\\u7528\\u3059\\u308b\\u5834\\u5408\\u304c\\u3042\\u308a\\u307e\\u3059\\u3002 \\u305d\\u308c\\u3089\\u306f\\u500b\\u4eba\\u60c5\\u5831\\u3092\\u76f4\\u63a5\\u4fdd\\u5b58\\u3059\\u308b\\u306e\\u3067\\u306f\\u306a\\u304f\\u3001\\u30d6\\u30e9\\u30a6\\u30b6\\u3068\\u30a4\\u30f3\\u30bf\\u30fc\\u30cd\\u30c3\\u30c8 \\u30c7\\u30d0\\u30a4\\u30b9\\u3092\\u4e00\\u610f\\u306b\\u8b58\\u5225\\u3059\\u308b\\u3053\\u3068\\u306b\\u57fa\\u3065\\u3044\\u3066\\u3044\\u307e\\u3059\\u3002 \\u3053\\u308c\\u3089\\u306e Cookie \\u3092\\u8a31\\u53ef\\u3057\\u306a\\u3044\\u5834\\u5408\\u3001\\u30bf\\u30fc\\u30b2\\u30c3\\u30c8\\u3092\\u7d5e\\u3063\\u305f\\u5e83\\u544a\\u304c\\u8868\\u793a\\u3055\\u308c\\u306a\\u304f\\u306a\\u308a\\u307e\\u3059\\u3002\",\"required\":\"0\"},\"PZBLwtiaQkoHmNHu\":{\"title\":\"\\u6a5f\\u80fd\\u6027\\u30af\\u30c3\\u30ad\\u30fc\",\"description\":\"\\u3053\\u308c\\u3089\\u306e Cookie \\u306b\\u3088\\u308a\\u3001\\u30a6\\u30a7\\u30d6\\u30b5\\u30a4\\u30c8\\u306e\\u6a5f\\u80fd\\u304c\\u5f37\\u5316\\u3055\\u308c\\u3001\\u30d1\\u30fc\\u30bd\\u30ca\\u30e9\\u30a4\\u30ba\\u304c\\u53ef\\u80fd\\u306b\\u306a\\u308a\\u307e\\u3059\\u3002 \\u305d\\u308c\\u3089\\u306f\\u3001\\u5f53\\u793e\\u307e\\u305f\\u306f\\u5f53\\u793e\\u306e\\u30da\\u30fc\\u30b8\\u306b\\u30b5\\u30fc\\u30d3\\u30b9\\u3092\\u8ffd\\u52a0\\u3057\\u305f\\u30b5\\u30fc\\u30c9\\u30d1\\u30fc\\u30c6\\u30a3\\u30d7\\u30ed\\u30d0\\u30a4\\u30c0\\u30fc\\u306b\\u3088\\u3063\\u3066\\u8a2d\\u5b9a\\u3055\\u308c\\u308b\\u5834\\u5408\\u304c\\u3042\\u308a\\u307e\\u3059\\u3002 \\u3053\\u308c\\u3089\\u306e Cookie \\u3092\\u8a31\\u53ef\\u3057\\u306a\\u3044\\u5834\\u5408\\u3001\\u3053\\u308c\\u3089\\u306e\\u30b5\\u30fc\\u30d3\\u30b9\\u306e\\u4e00\\u90e8\\u307e\\u305f\\u306f\\u3059\\u3079\\u3066\\u304c\\u6b63\\u3057\\u304f\\u6a5f\\u80fd\\u3057\\u306a\\u3044\\u53ef\\u80fd\\u6027\\u304c\\u3042\\u308a\\u307e\\u3059\\u3002\",\"required\":\"0\"},\"AhjHNZbaKFygtlfb\":{\"title\":\"\\u30d1\\u30d5\\u30a9\\u30fc\\u30de\\u30f3\\u30b9 Cookie\",\"description\":\"\\u3053\\u308c\\u3089\\u306e Cookie \\u3092\\u4f7f\\u7528\\u3059\\u308b\\u3068\\u3001\\u8a2a\\u554f\\u8005\\u3068\\u30c8\\u30e9\\u30d5\\u30a3\\u30c3\\u30af \\u30bd\\u30fc\\u30b9\\u3092\\u30ab\\u30a6\\u30f3\\u30c8\\u3067\\u304d\\u308b\\u305f\\u3081\\u3001\\u30b5\\u30a4\\u30c8\\u306e\\u30d1\\u30d5\\u30a9\\u30fc\\u30de\\u30f3\\u30b9\\u3092\\u6e2c\\u5b9a\\u304a\\u3088\\u3073\\u6539\\u5584\\u3067\\u304d\\u307e\\u3059\\u3002 \\u305d\\u308c\\u3089\\u306f\\u3001\\u6700\\u3082\\u4eba\\u6c17\\u306e\\u3042\\u308b\\u30da\\u30fc\\u30b8\\u3068\\u6700\\u3082\\u4eba\\u6c17\\u306e\\u306a\\u3044\\u30da\\u30fc\\u30b8\\u3092\\u628a\\u63e1\\u3057\\u3001\\u8a2a\\u554f\\u8005\\u304c\\u30b5\\u30a4\\u30c8\\u5185\\u3092\\u3069\\u306e\\u3088\\u3046\\u306b\\u79fb\\u52d5\\u3059\\u308b\\u304b\\u3092\\u628a\\u63e1\\u3059\\u308b\\u306e\\u306b\\u5f79\\u7acb\\u3061\\u3001\\u30a8\\u30af\\u30b9\\u30da\\u30ea\\u30a8\\u30f3\\u30b9\\u3092\\u6700\\u9069\\u5316\\u3059\\u308b\\u306e\\u306b\\u5f79\\u7acb\\u3061\\u307e\\u3059. \\u3053\\u308c\\u3089\\u306e Cookie \\u304c\\u53ce\\u96c6\\u3059\\u308b\\u3059\\u3079\\u3066\\u306e\\u60c5\\u5831\\u306f\\u96c6\\u7d04\\u3055\\u308c\\u308b\\u305f\\u3081\\u3001\\u533f\\u540d\\u5316\\u3055\\u308c\\u307e\\u3059\\u3002 \\u3053\\u308c\\u3089\\u306e Cookie \\u3092\\u8a31\\u53ef\\u3057\\u306a\\u3044\\u5834\\u5408\\u3001\\u3053\\u306e\\u65b9\\u6cd5\\u3067\\u30c7\\u30fc\\u30bf\\u3092\\u4f7f\\u7528\\u3059\\u308b\\u3053\\u3068\\u306f\\u3067\\u304d\\u307e\\u305b\\u3093\\u3002\",\"required\":\"0\"},\"ALjbSdmxfAcJpwhj\":{\"title\":\"\\u7d76\\u5bfe\\u306b\\u5fc5\\u8981\",\"description\":\"\\u3053\\u308c\\u3089\\u306e Cookie \\u306f\\u3001\\u5f53\\u793e\\u306e Web \\u30b5\\u30a4\\u30c8\\u304c\\u9069\\u5207\\u306b\\u6a5f\\u80fd\\u3059\\u308b\\u305f\\u3081\\u306b\\u5fc5\\u8981\\u3067\\u3042\\u308a\\u3001\\u5f53\\u793e\\u306e\\u30b7\\u30b9\\u30c6\\u30e0\\u3067\\u30aa\\u30d5\\u306b\\u3059\\u308b\\u3053\\u3068\\u306f\\u3067\\u304d\\u307e\\u305b\\u3093\\u3002 \\u305d\\u308c\\u3089\\u306f\\u901a\\u5e38\\u3001\\u30d7\\u30e9\\u30a4\\u30d0\\u30b7\\u30fc\\u8a2d\\u5b9a\\u306e\\u8a2d\\u5b9a\\u3001\\u30ed\\u30b0\\u30a4\\u30f3\\u307e\\u305f\\u306f\\u30d5\\u30a9\\u30fc\\u30e0\\u3078\\u306e\\u5165\\u529b\\u3001\\u307e\\u305f\\u306f\\u8981\\u6c42\\u3057\\u305f\\u30b5\\u30fc\\u30d3\\u30b9\\u3092\\u63d0\\u4f9b\\u3059\\u308b\\u305f\\u3081\\u306b\\u4e0d\\u53ef\\u6b20\\u306a\\u5834\\u5408\\u306a\\u3069\\u3001\\u30b5\\u30fc\\u30d3\\u30b9\\u306e\\u8981\\u6c42\\u306b\\u76f8\\u5f53\\u3059\\u308b\\u30e6\\u30fc\\u30b6\\u30fc\\u306e\\u30a2\\u30af\\u30b7\\u30e7\\u30f3\\u306b\\u5fdc\\u3058\\u3066\\u306e\\u307f\\u8a2d\\u5b9a\\u3055\\u308c\\u307e\\u3059\\u3002 \\u3053\\u308c\\u3089\\u306e Cookie \\u3092\\u30aa\\u30d7\\u30c8\\u30a2\\u30a6\\u30c8\\u3059\\u308b\\u3053\\u3068\\u306f\\u3067\\u304d\\u307e\\u305b\\u3093\\u3002 \\u3053\\u308c\\u3089\\u306e Cookie \\u3092\\u30d6\\u30ed\\u30c3\\u30af\\u307e\\u305f\\u306f\\u8b66\\u544a\\u3059\\u308b\\u3088\\u3046\\u306b\\u30d6\\u30e9\\u30a6\\u30b6\\u3092\\u8a2d\\u5b9a\\u3067\\u304d\\u307e\\u3059\\u304c\\u3001\\u305d\\u3046\\u3059\\u308b\\u3068\\u3001\\u30b5\\u30a4\\u30c8\\u306e\\u4e00\\u90e8\\u304c\\u6a5f\\u80fd\\u3057\\u306a\\u304f\\u306a\\u308a\\u307e\\u3059\\u3002 \\u3053\\u308c\\u3089\\u306e Cookie \\u306f\\u3001\\u500b\\u4eba\\u3092\\u7279\\u5b9a\\u3067\\u304d\\u308b\\u60c5\\u5831\\u3092\\u4fdd\\u5b58\\u3057\\u307e\\u305b\\u3093\\u3002\",\"required\":\"0\"}}}'),
(179, 44, 'ko', '{\"cookie_settings_modal_message\":\"<p>\\uadc0\\ud558\\uac00 \\ub2f9\\uc0ac \\uc6f9\\uc0ac\\uc774\\ud2b8\\ub97c \\ubc29\\ubb38\\ud558\\uba74 \\ub300\\ubd80\\ubd84 \\ucfe0\\ud0a4 \\ud615\\ud0dc\\ub85c \\uadc0\\ud558\\uc758 \\ube0c\\ub77c\\uc6b0\\uc800\\uc5d0 \\uc815\\ubcf4\\ub97c \\uc800\\uc7a5\\ud558\\uac70\\ub098 \\uac80\\uc0c9\\ud560 \\uc218 \\uc788\\uc2b5\\ub2c8\\ub2e4. \\uc774 \\uc815\\ubcf4\\ub294 \\uadc0\\ud558, \\uadc0\\ud558\\uc758 \\uae30\\ubcf8 \\uc124\\uc815 \\ub610\\ub294 \\uadc0\\ud558\\uc758 \\uc7a5\\uce58\\uc5d0 \\uad00\\ud55c \\uac83\\uc77c \\uc218 \\uc788\\uc73c\\uba70 \\uadc0\\ud558\\uac00 \\uae30\\ub300\\ud558\\ub294 \\ub300\\ub85c \\uc0ac\\uc774\\ud2b8\\uac00 \\uc791\\ub3d9\\ud558\\ub3c4\\ub85d \\ud558\\ub294 \\ub370 \\uc8fc\\ub85c \\uc0ac\\uc6a9\\ub429\\ub2c8\\ub2e4. \\uc774 \\uc815\\ubcf4\\ub294 \\uc77c\\ubc18\\uc801\\uc73c\\ub85c \\uadc0\\ud558\\ub97c \\uc9c1\\uc811 \\uc2dd\\ubcc4\\ud558\\uc9c0\\ub294 \\uc54a\\uc9c0\\ub9cc \\ubcf4\\ub2e4 \\uac1c\\uc778\\ud654\\ub41c \\uc6f9 \\uacbd\\ud5d8\\uc744 \\uc81c\\uacf5\\ud560 \\uc218 \\uc788\\uc2b5\\ub2c8\\ub2e4. \\ub2f9\\uc0ac\\ub294 \\uadc0\\ud558\\uc758 \\uac1c\\uc778 \\uc815\\ubcf4 \\ubcf4\\ud638 \\uad8c\\ub9ac\\ub97c \\uc874\\uc911\\ud558\\ubbc0\\ub85c \\uc77c\\ubd80 \\uc720\\ud615\\uc758 \\ucfe0\\ud0a4\\ub97c \\ud5c8\\uc6a9\\ud558\\uc9c0 \\uc54a\\ub3c4\\ub85d \\uc120\\ud0dd\\ud560 \\uc218 \\uc788\\uc2b5\\ub2c8\\ub2e4. \\uc790\\uc138\\ud55c \\ub0b4\\uc6a9\\uc744 \\uc54c\\uc544\\ubcf4\\uace0 \\uae30\\ubcf8 \\uc124\\uc815\\uc744 \\uad00\\ub9ac\\ud558\\ub824\\uba74 \\ub2e4\\ub978 \\ubc94\\uc8fc \\uc81c\\ubaa9\\uc744 \\ud074\\ub9ad\\ud558\\uc2ed\\uc2dc\\uc624. \\uc77c\\ubd80 \\uc720\\ud615\\uc758 \\ucfe0\\ud0a4\\ub97c \\ucc28\\ub2e8\\ud558\\uba74 \\uadc0\\ud558\\uc758 \\uc0ac\\uc774\\ud2b8 \\uacbd\\ud5d8\\uacfc \\ub2f9\\uc0ac\\uac00 \\uc81c\\uacf5\\ud560 \\uc218 \\uc788\\ub294 \\uc11c\\ube44\\uc2a4\\uc5d0 \\uc601\\ud5a5\\uc744 \\ubbf8\\uce60 \\uc218 \\uc788\\uc2b5\\ub2c8\\ub2e4.<\\/p