4\\ubd80\\uac00 \\uc81c\\ub300\\ub85c \\uc791\\ub3d9\\ud558\\uc9c0 \\uc54a\\uc744 \\uc218 \\uc788\\uc2b5\\ub2c8\\ub2e4.\",\"required\":\"0\"},\"HFXunBzWNHzKRleW\":{\"title\":\"\\uc131\\ub2a5 \\ucfe0\\ud0a4\",\"description\":\"\\uc774 \\ucfe0\\ud0a4\\ub97c \\uc0ac\\uc6a9\\ud558\\uba74 \\ubc29\\ubb38 \\ubc0f \\ud2b8\\ub798\\ud53d \\uc18c\\uc2a4\\ub97c \\uacc4\\uc0b0\\ud558\\uc5ec \\uc0ac\\uc774\\ud2b8 \\uc131\\ub2a5\\uc744 \\uce21\\uc815\\ud558\\uace0 \\uac1c\\uc120\\ud560 \\uc218 \\uc788\\uc2b5\\ub2c8\\ub2e4. \\uac00\\uc7a5 \\uc778\\uae30 \\uc788\\ub294 \\ud398\\uc774\\uc9c0\\uc640 \\uac00\\uc7a5 \\uc778\\uae30 \\uc5c6\\ub294 \\ud398\\uc774\\uc9c0\\ub97c \\ud30c\\uc545\\ud558\\uace0 \\ubc29\\ubb38\\uc790\\uac00 \\uc0ac\\uc774\\ud2b8\\uc5d0\\uc11c \\uc5b4\\ub5bb\\uac8c \\uc774\\ub3d9\\ud558\\ub294\\uc9c0 \\ud655\\uc778\\ud558\\uc5ec \\uc0ac\\uc6a9\\uc790 \\uacbd\\ud5d8\\uc744 \\ucd5c\\uc801\\ud654\\ud558\\ub294 \\ub370 \\ub3c4\\uc6c0\\uc774 \\ub429\\ub2c8\\ub2e4. \\uc774\\ub7ec\\ud55c \\ucfe0\\ud0a4\\uac00 \\uc218\\uc9d1\\ud558\\ub294 \\ubaa8\\ub4e0 \\uc815\\ubcf4\\ub294 \\uc9d1\\uacc4\\ub418\\ubbc0\\ub85c \\uc775\\uba85\\uc785\\ub2c8\\ub2e4. \\uc774\\ub7ec\\ud55c \\ucfe0\\ud0a4\\ub97c \\ud5c8\\uc6a9\\ud558\\uc9c0 \\uc54a\\uc73c\\uba74 \\uc774\\ub7ec\\ud55c \\ubc29\\uc2dd\\uc73c\\ub85c \\ub370\\uc774\\ud130\\ub97c \\uc0ac\\uc6a9\\ud560 \\uc218 \\uc5c6\\uc2b5\\ub2c8\\ub2e4.\",\"required\":\"0\"},\"iphXqmvLYzUFRSFi\":{\"title\":\"\\uaf2d \\ud544\\uc694\\ud55c\",\"description\":\"\\uc774\\ub7ec\\ud55c \\ucfe0\\ud0a4\\ub294 \\ub2f9\\uc0ac \\uc6f9\\uc0ac\\uc774\\ud2b8\\uac00 \\uc81c\\ub300\\ub85c \\uc791\\ub3d9\\ud558\\ub294 \\ub370 \\ud544\\uc694\\ud558\\uba70 \\ub2f9\\uc0ac \\uc2dc\\uc2a4\\ud15c\\uc5d0\\uc11c \\ub04c \\uc218 \\uc5c6\\uc2b5\\ub2c8\\ub2e4. \\uc77c\\ubc18\\uc801\\uc73c\\ub85c \\uac1c\\uc778 \\uc815\\ubcf4 \\uae30\\ubcf8 \\uc124\\uc815, \\ub85c\\uadf8\\uc778 \\ub610\\ub294 \\uc591\\uc2dd \\uc791\\uc131\\uacfc \\uac19\\uc774 \\uc11c\\ube44\\uc2a4 \\uc694\\uccad\\uc5d0 \\ud574\\ub2f9\\ud558\\ub294 \\uadc0\\ud558\\uc758 \\uc791\\uc5c5 \\ub610\\ub294 \\uadc0\\ud558\\uac00 \\uc694\\uccad\\ud55c \\uc11c\\ube44\\uc2a4\\ub97c \\uc81c\\uacf5\\ud558\\ub294 \\ub370 \\ud544\\uc218\\uc801\\uc778 \\uc791\\uc5c5\\uc5d0 \\ub300\\ud55c \\uc751\\ub2f5\\uc73c\\ub85c\\ub9cc \\uc124\\uc815\\ub429\\ub2c8\\ub2e4. \\uadc0\\ud558\\ub294 \\uc774\\ub7ec\\ud55c \\ucfe0\\ud0a4\\ub97c \\uac70\\ubd80\\ud560 \\uc218 \\uc5c6\\uc2b5\\ub2c8\\ub2e4. \\uc774\\ub7ec\\ud55c \\ucfe0\\ud0a4\\ub97c \\ucc28\\ub2e8\\ud558\\uac70\\ub098 \\uacbd\\uace0\\ud558\\ub3c4\\ub85d \\ube0c\\ub77c\\uc6b0\\uc800\\ub97c \\uc124\\uc815\\ud560 \\uc218 \\uc788\\uc9c0\\ub9cc \\uadf8\\ub807\\uac8c \\ud558\\uba74 \\uc0ac\\uc774\\ud2b8\\uc758 \\uc77c\\ubd80\\uac00 \\uc791\\ub3d9\\ud558\\uc9c0 \\uc54a\\uc744 \\uc218 \\uc788\\uc2b5\\ub2c8\\ub2e4. \\uc774 \\ucfe0\\ud0a4\\ub294 \\uac1c\\uc778 \\uc2dd\\ubcc4 \\uc815\\ubcf4\\ub97c \\uc800\\uc7a5\\ud558\\uc9c0 \\uc54a\\uc2b5\\ub2c8\\ub2e4.\",\"required\":\"0\"}}}'),
(180, 44, 'ms', '{\"cookie_settings_modal_message\":\"<p>Apabila anda melawati mana-mana tapak web kami, ia mungkin menyimpan atau mendapatkan maklumat pada penyemak imbas anda, kebanyakannya dalam bentuk kuki. Maklumat ini mungkin mengenai anda, pilihan anda atau peranti anda dan kebanyakannya digunakan untuk menjadikan tapak berfungsi seperti yang anda harapkan. Maklumat tersebut biasanya tidak mengenal pasti anda secara langsung, tetapi ia boleh memberi anda pengalaman web yang lebih diperibadikan. Kerana kami menghormati hak privasi anda, anda boleh memilih untuk tidak membenarkan beberapa jenis kuki. Klik pada tajuk kategori yang berbeza untuk mengetahui lebih lanjut dan mengurus pilihan anda. Sila ambil perhatian, bahawa menyekat beberapa jenis kuki boleh memberi kesan kepada pengalaman anda terhadap tapak dan perkhidmatan yang kami boleh tawarkan.<\\/p>\",\"cookie_settings_modal_items\":{\"YIeTALpPGHWWJUOy\":{\"title\":\"Menyasarkan Kuki\",\"description\":\"Kuki ini mungkin ditetapkan melalui tapak kami oleh rakan kongsi pengiklanan kami. Mereka mungkin digunakan oleh syarikat tersebut untuk membina profil minat anda dan menunjukkan kepada anda iklan yang berkaitan di tapak lain. Mereka tidak menyimpan maklumat peribadi secara langsung tetapi berdasarkan pengecaman unik pelayar dan peranti internet anda. Jika anda tidak membenarkan kuki ini, anda akan mengalami kurang pengiklanan disasarkan.\",\"required\":\"0\"},\"ZPLhwxbCXfEoJphB\":{\"title\":\"Kuki Berfungsi\",\"description\":\"Kuki ini membolehkan tapak web menyediakan kefungsian dan pemperibadian yang dipertingkatkan. Ia mungkin ditetapkan oleh kami atau oleh pembekal pihak ketiga yang perkhidmatannya telah kami tambahkan pada halaman kami. Jika anda tidak membenarkan kuki ini maka beberapa atau semua perkhidmatan ini mungkin tidak berfungsi dengan baik.\",\"required\":\"0\"},\"qewQcbyteciphrFL\":{\"title\":\"Kuki Prestasi\",\"description\":\"Kuki ini membolehkan kami mengira lawatan dan sumber trafik supaya kami boleh mengukur dan meningkatkan prestasi tapak kami. Mereka membantu kami mengetahui halaman mana yang paling dan paling kurang popular dan melihat cara pelawat bergerak di sekitar tapak, yang membantu kami mengoptimumkan pengalaman anda. Semua maklumat yang dikumpul kuki ini adalah diagregatkan dan oleh itu tanpa nama. Jika anda tidak membenarkan kuki ini, kami tidak akan dapat menggunakan data anda dengan cara ini.\",\"required\":\"0\"},\"QmVIXjJftfijaCYW\":{\"title\":\"Sangat Perlu\",\"description\":\"Kuki ini diperlukan untuk tapak web kami berfungsi dengan baik dan tidak boleh dimatikan dalam sistem kami. Ia biasanya hanya ditetapkan sebagai tindak balas kepada tindakan yang dibuat oleh anda yang berjumlah permintaan untuk perkhidmatan, seperti menetapkan keutamaan privasi anda, log masuk atau mengisi borang, atau tempat ia penting untuk menyediakan perkhidmatan yang anda minta. Anda tidak boleh menarik diri daripada kuki ini. Anda boleh menetapkan penyemak imbas anda untuk menyekat atau memberi amaran kepada anda tentang kuki ini, tetapi jika anda melakukannya, sesetengah bahagian tapak tidak akan berfungsi. Kuki ini tidak menyimpan sebarang maklumat yang boleh dikenal pasti secara peribadi.\",\"required\":\"0\"}}}');
