(186, 44, 'vi', '{\"cookie_settings_modal_message\":\"<p>Khi b\\u1ea1n truy c\\u1eadp b\\u1ea5t k\\u1ef3 trang web n\\u00e0o c\\u1ee7a ch\\u00fang t\\u00f4i, n\\u00f3 c\\u00f3 th\\u1ec3 l\\u01b0u tr\\u1eef ho\\u1eb7c truy xu\\u1ea5t th\\u00f4ng tin tr\\u00ean tr\\u00ecnh duy\\u1ec7t c\\u1ee7a b\\u1ea1n, ch\\u1ee7 y\\u1ebfu \\u1edf d\\u1ea1ng cookie. Th\\u00f4ng tin n\\u00e0y c\\u00f3 th\\u1ec3 l\\u00e0 v\\u1ec1 b\\u1ea1n, t\\u00f9y ch\\u1ecdn c\\u1ee7a b\\u1ea1n ho\\u1eb7c thi\\u1ebft b\\u1ecb c\\u1ee7a b\\u1ea1n v\\u00e0 ch\\u1ee7 y\\u1ebfu \\u0111\\u01b0\\u1ee3c s\\u1eed d\\u1ee5ng \\u0111\\u1ec3 l\\u00e0m cho trang web ho\\u1ea1t \\u0111\\u1ed9ng nh\\u01b0 b\\u1ea1n mong \\u0111\\u1ee3i. Th\\u00f4ng tin th\\u01b0\\u1eddng kh\\u00f4ng tr\\u1ef1c ti\\u1ebfp nh\\u1eadn d\\u1ea1ng b\\u1ea1n, nh\\u01b0ng n\\u00f3 c\\u00f3 th\\u1ec3 mang l\\u1ea1i cho b\\u1ea1n tr\\u1ea3i nghi\\u1ec7m web \\u0111\\u01b0\\u1ee3c c\\u00e1 nh\\u00e2n h\\u00f3a h\\u01a1n. V\\u00ec ch\\u00fang t\\u00f4i t\\u00f4n tr\\u1ecdng quy\\u1ec1n ri\\u00eang t\\u01b0 c\\u1ee7a b\\u1ea1n n\\u00ean b\\u1ea1n c\\u00f3 th\\u1ec3 ch\\u1ecdn kh\\u00f4ng cho ph\\u00e9p m\\u1ed9t s\\u1ed1 lo\\u1ea1i cookie. Nh\\u1ea5p v\\u00e0o c\\u00e1c ti\\u00eau \\u0111\\u1ec1 danh m\\u1ee5c kh\\u00e1c nhau \\u0111\\u1ec3 t\\u00ecm hi\\u1ec3u th\\u00eam v\\u00e0 qu\\u1ea3n l\\u00fd t\\u00f9y ch\\u1ecdn c\\u1ee7a b\\u1ea1n. Xin l\\u01b0u \\u00fd r\\u1eb1ng vi\\u1ec7c ch\\u1eb7n m\\u1ed9t s\\u1ed1 lo\\u1ea1i cookie c\\u00f3 th\\u1ec3 \\u1ea3nh h\\u01b0\\u1edfng \\u0111\\u1ebfn tr\\u1ea3i nghi\\u1ec7m c\\u1ee7a b\\u1ea1n \\u0111\\u1ed1i v\\u1edbi trang web v\\u00e0 c\\u00e1c d\\u1ecbch v\\u1ee5 m\\u00e0 ch\\u00fang t\\u00f4i c\\u00f3 th\\u1ec3 cung c\\u1ea5p.<\\/p><p><br><\\/p><p><br><\\/p><p><br><\\/p>\",\"cookie_settings_modal_items\":{\"iyEdnOWkOhTZJLMD\":{\"title\":\"Nh\\u1eafm m\\u1ee5c ti\\u00eau cookie\",\"description\":\"C\\u00e1c cookie n\\u00e0y c\\u00f3 th\\u1ec3 \\u0111\\u01b0\\u1ee3c \\u0111\\u1eb7t th\\u00f4ng qua trang web c\\u1ee7a ch\\u00fang t\\u00f4i b\\u1edfi c\\u00e1c \\u0111\\u1ed1i t\\u00e1c qu\\u1ea3ng c\\u00e1o c\\u1ee7a ch\\u00fang t\\u00f4i. Ch\\u00fang c\\u00f3 th\\u1ec3 \\u0111\\u01b0\\u1ee3c c\\u00e1c c\\u00f4ng ty \\u0111\\u00f3 s\\u1eed d\\u1ee5ng \\u0111\\u1ec3 x\\u00e2y d\\u1ef1ng h\\u1ed3 s\\u01a1 v\\u1ec1 s\\u1edf th\\u00edch c\\u1ee7a b\\u1ea1n v\\u00e0 hi\\u1ec3n th\\u1ecb cho b\\u1ea1n c\\u00e1c qu\\u1ea3ng c\\u00e1o c\\u00f3 li\\u00ean quan tr\\u00ean c\\u00e1c trang web kh\\u00e1c. Ch\\u00fang kh\\u00f4ng l\\u01b0u tr\\u1eef tr\\u1ef1c ti\\u1ebfp th\\u00f4ng tin c\\u00e1 nh\\u00e2n m\\u00e0 d\\u1ef1a tr\\u00ean vi\\u1ec7c nh\\u1eadn d\\u1ea1ng duy nh\\u1ea5t tr\\u00ecnh duy\\u1ec7t v\\u00e0 thi\\u1ebft b\\u1ecb internet c\\u1ee7a b\\u1ea1n. N\\u1ebfu b\\u1ea1n kh\\u00f4ng cho ph\\u00e9p nh\\u1eefng cookie n\\u00e0y, b\\u1ea1n s\\u1ebd \\u00edt g\\u1eb7p ph\\u1ea3i qu\\u1ea3ng c\\u00e1o \\u0111\\u01b0\\u1ee3c nh\\u1eafm m\\u1ee5c ti\\u00eau h\\u01a1n.\",\"required\":\"0\"},\"bJNMEjBaoXaRJmYO\":{\"title\":\"Cookie ch\\u1ee9c n\\u0103ng\",\"description\":\"Nh\\u1eefng cookie n\\u00e0y cho ph\\u00e9p trang web cung c\\u1ea5p ch\\u1ee9c n\\u0103ng v\\u00e0 c\\u00e1 nh\\u00e2n h\\u00f3a n\\u00e2ng cao. Ch\\u00fang c\\u00f3 th\\u1ec3 \\u0111\\u01b0\\u1ee3c \\u0111\\u1eb7t b\\u1edfi ch\\u00fang t\\u00f4i ho\\u1eb7c b\\u1edfi c\\u00e1c nh\\u00e0 cung c\\u1ea5p b\\u00ean th\\u1ee9 ba c\\u00f3 d\\u1ecbch v\\u1ee5 m\\u00e0 ch\\u00fang t\\u00f4i \\u0111\\u00e3 th\\u00eam v\\u00e0o c\\u00e1c trang c\\u1ee7a m\\u00ecnh. N\\u1ebfu b\\u1ea1n kh\\u00f4ng cho ph\\u00e9p nh\\u1eefng cookie n\\u00e0y th\\u00ec m\\u1ed9t s\\u1ed1 ho\\u1eb7c t\\u1ea5t c\\u1ea3 c\\u00e1c d\\u1ecbch v\\u1ee5 n\\u00e0y c\\u00f3 th\\u1ec3 kh\\u00f4ng ho\\u1ea1t \\u0111\\u1ed9ng b\\u00ecnh th\\u01b0\\u1eddng.\",\"required\":\"0\"},\"yacpKHXarNNxvlbQ\":{\"title\":\"Cookie hi\\u1ec7u su\\u1ea5t\",\"description\":\"Nh\\u1eefng cookie n\\u00e0y cho ph\\u00e9p ch\\u00fang t\\u00f4i \\u0111\\u1ebfm s\\u1ed1 l\\u01b0\\u1ee3t truy c\\u1eadp v\\u00e0 ngu\\u1ed3n l\\u01b0u l\\u01b0\\u1ee3ng truy c\\u1eadp \\u0111\\u1ec3 ch\\u00fang t\\u00f4i c\\u00f3 th\\u1ec3 \\u0111o l\\u01b0\\u1eddng v\\u00e0 c\\u1ea3i thi\\u1ec7n hi\\u1ec7u su\\u1ea5t trang web c\\u1ee7a m\\u00ecnh. Ch\\u00fang gi\\u00fap ch\\u00fang t\\u00f4i bi\\u1ebft trang n\\u00e0o ph\\u1ed5 bi\\u1ebfn nh\\u1ea5t v\\u00e0 \\u00edt ph\\u1ed5 bi\\u1ebfn nh\\u1ea5t, \\u0111\\u1ed3ng th\\u1eddi xem c\\u00e1ch kh\\u00e1ch truy c\\u1eadp di chuy\\u1ec3n quanh trang web, \\u0111i\\u1ec1u n\\u00e0y gi\\u00fap ch\\u00fang t\\u00f4i t\\u1ed1i \\u01b0u h\\u00f3a tr\\u1ea3i nghi\\u1ec7m c\\u1ee7a b\\u1ea1n. T\\u1ea5t c\\u1ea3 th\\u00f4ng tin m\\u00e0 c\\u00e1c cookie n\\u00e0y thu th\\u1eadp \\u0111\\u01b0\\u1ee3c t\\u1ed5ng h\\u1ee3p v\\u00e0 do \\u0111\\u00f3 \\u0111\\u01b0\\u1ee3c \\u1ea9n danh. N\\u1ebfu b\\u1ea1n kh\\u00f4ng cho ph\\u00e9p nh\\u1eefng cookie n\\u00e0y, ch\\u00fang t\\u00f4i s\\u1ebd kh\\u00f4ng th\\u1ec3 s\\u1eed d\\u1ee5ng d\\u1eef li\\u1ec7u c\\u1ee7a b\\u1ea1n theo c\\u00e1ch n\\u00e0y.\",\"required\":\"0\"},\"tyYaXrcOmvVXWUie\":{\"title\":\"Ho\\u00e0n to\\u00e0n c\\u1ea7n thi\\u1ebft\",\"description\":\"Nh\\u1eefng cookie n\\u00e0y c\\u1ea7n thi\\u1ebft \\u0111\\u1ec3 trang web c\\u1ee7a ch\\u00fang t\\u00f4i ho\\u1ea1t \\u0111\\u1ed9ng b\\u00ecnh th\\u01b0\\u1eddng v\\u00e0 kh\\u00f4ng th\\u1ec3 t\\u1eaft trong h\\u1ec7 th\\u1ed1ng c\\u1ee7a ch\\u00fang t\\u00f4i. Ch\\u00fang th\\u01b0\\u1eddng ch\\u1ec9 \\u0111\\u01b0\\u1ee3c \\u0111\\u1eb7t \\u0111\\u1ec3 ph\\u1ea3n h\\u1ed3i c\\u00e1c h\\u00e0nh \\u0111\\u1ed9ng do b\\u1ea1n th\\u1ef1c hi\\u1ec7n d\\u1eabn \\u0111\\u1ebfn y\\u00eau c\\u1ea7u d\\u1ecbch v\\u1ee5, ch\\u1eb3ng h\\u1ea1n nh\\u01b0 \\u0111\\u1eb7t t\\u00f9y ch\\u1ecdn quy\\u1ec1n ri\\u00eang t\\u01b0, \\u0111\\u0103ng nh\\u1eadp ho\\u1eb7c \\u0111i\\u1ec1n v\\u00e0o bi\\u1ec3u m\\u1eabu ho\\u1eb7c khi ch\\u00fang c\\u1ea7n thi\\u1ebft \\u0111\\u1ec3 cung c\\u1ea5p cho b\\