(192, 4, 'id', '{\"first_column\":{\"title\":\"Misi kita\",\"value\":\"<p><font color=\\\"#ffffff\\\">Misi kami adalah untuk meningkatkan keterampilan teknis dan profesional orang-orang di industri real estat, dengan menyediakan platform yang mudah digunakan di mana setiap orang dapat membagikan keahliannya dengan memberikan kursus berbayar atau gratis.<\\/font><\\/p><p style=\\\"text-align: center; \\\"><a href=\\\"\\/pages\\/about\\\" target=\\\"_blank\\\"><font color=\\\"#ffffff\\\">Informasi lebih lanjut<\\/font><\\/a><\\/p>\"},\"second_column\":{\"title\":\"Audiens sasaran\",\"value\":\"<p><font color=\\\"#ffffff\\\">- Tukang Real Estat<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Agen real estat<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Pengembang Realestate<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Manajer proyek real estat.<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Investor real estat<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Pengusaha properti<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Pemasar real estat<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Konsultan Properti<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Tutor real estat<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Pemuda &amp; Pelajar<\\/font><\\/p>\"},\"third_column\":{\"title\":\"Kategori Teratas\",\"value\":\"<p><font color=\\\"#ffffff\\\">- Dekorasi rumah<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Lukisan Dinding<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Pekerjaan pertukangan<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Lansekap<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Pipa bekerja<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Ubin berfungsi<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Listrik bekerja<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Kursus untuk anak-anak<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Pemasaran real estat<\\/font><\\/p><p><font color=\\\"#ffffff\\\">- Manajemen proyek<\\/font><\\/p>\"},\"forth_column\":{\"title\"