INSERT INTO `testimonial_translations` (`id`, `testimonial_id`, `locale`, `user_name`, `user_bio`, `comment`) VALUES
(1, 2, 'en', 'Harold Newman', 'Professional Plumber', 'As a plumbing professional for 40 years, I loved my job, and I have no other knowledge. Because I was older than 60, my health was not as efficient as it should have been, and I suffered from loneliness and emptiness so much that I had to see a psychotherapist. After hearing about KEMECADMEY, I thought, \"Why not spend my free time teaching young people the profession of plumbing?\".&nbsp; It was the best decision I\'ve ever made. Honestly, it was amazing. As a result of my courses, I felt that my community still needed me and that I had value to offer. Thanks for allowing me to share my experience and bringing me out of my isolation'),
(2, 3, 'en', 'Sanaa Magdy', 'Mother', 'I am a mother of twin children. They are 15 years old. I believe that every child should learn his profession that needs muscular efforts from handicrafts or realestate professions for educational and financial reasons. Despite my efforts, I was unable to find a place where my children could select courses that were appropriate for them. As soon as I found Kemecademy, I was excited because I could choose among hundreds of Trainers and hundreds of courses in my area. According to my research, Kemecademy is a unique service that will positively impact the world of vocational training.'),
(3, 4, 'en', 'Jonas Hennes', 'Managing Director', '<div>I am the director of an architectural real estate firm. I have many projects in which I work with craftsmen, construction workers, painters, carpenters, plumbers, etc. I needed to take practical courses from experts in order to review their work and ensure that it was of high quality, and this is what I found on your wonderful platform, which saved me a great deal of time, effort, and money. As a result of the excellent experience, I am now preparing myself and my employees to take courses in management, marketing, and project management.</div>'),
(6, 2, 'ar', 'هارولد نيومان', 'سباك صحي', '<div><font color=\"#000000\" face=\"Arial\"><span style=\"font-size: 14.6667px; white-space: pre-wrap;\">قضيت 40 سنه من عمري في مهنه السباكة.أحببتها ولا أعرف غيرها ومنذ تعدى عمري الستين عاما لم تكن صحتي بالكفاءة المطلوبة لمهنتي وعانيت كثيرا من الفراغ والوحدة حتى انني اضطررت الى الذهاب الى معالج نفسي وعندما سمعت عن كيميكاديمي قلت لما لا اشغل وقت فراغي بتدريب الشباب على مهنه السباكة التي أبرع فيها .وكان هذا في تقديري أفضل قرار أتخذه بحياتي. كان الأمر رائعاً حقاً أخرجتني تلك الدورات التي أقدمها لهؤلاء الشباب من عزلتي واكتئابي وأحسست انه ما زال لي قيمة وأن هناك ما يمكن أن أقدمه لمجتمعي . شكراً لكم لاتاحة الفرصة لي على تقديم ما لدي من خبرات واخراجي من عزلتي</span></font></div>'),
(7, 2, 'es', 'Harold Newmann', 'Plomero profesional', '<div>Como plomero profesional durante 40 años, amaba mi trabajo y no tengo otro conocimiento. Debido a que tenía más de 60 años, mi salud no era tan eficiente como debería haber sido, y sufría tanto de soledad y vacío que tuve que ver a un psicoterapeuta. Después de escuchar sobre kemecademy, pensé: \"¿Por qué no dedicar mi tiempo libre a enseñar a los jóvenes la profesión de plomería?\". Fue la mejor decisión que he tomado. Honestamente, fue increíble. Como resultado de mis cursos, sentí que mi comunidad aún me necesitaba y que tenía valor para ofrecer. Gracias por permitirme compartir mi experiencia y sacarme de mi aislamiento.</div>'),
(8, 3, 'es', 'Saná Magdy', 'Madre', '<div>Soy madre de gemelos. Tienen 15 años. Creo que cada niño debe aprender su profesión que requiere esfuerzos musculares de las profesiones artesanales o inmobiliarias por razones educativas y financieras. A pesar de mis esfuerzos, no pude encontrar un lugar donde mis hijos pudieran seleccionar cursos que fueran apropiados para ellos. Tan pronto como encontré Kemecademy, me emocioné porque podía elegir entre cientos de entrenadores y cientos de cursos en mi área. Según mi investigación, Kemecademy es un servicio único que impactará positivamente en el mundo de la formación profesional.</div>'),
(9, 3, 'ar', 'سناء مجدي', 'أم', '<div>أنا أم لطفلين توأمين ، عمرهما 15 عامًا. أؤمن أن كل طفل يجب أن يتعلم مهنته من الحرف اليدوية أو المهن العقارية التي تحتاج لمجهود عضلي لأسباب تربوية ومالية. على الرغم من جهودي في البحث، لم أتمكن من العثور على مكان يستطيع فيه أطفالي اختيار الدورات التي تناسبهم. بمجرد أن وجدت كيميكاديمي، كنت متحمسة لأنني تمكنت من الاختيار من بين مئات المدربين ومئات الدورات في منطقتي. وفقًا لبحثي ، تعد كيميكاديمي خدمة فريدة من نوعها أعتقد أنها ستؤثر بشكل إيجابي على عالم التدريب المهني.</div>'),
(10, 4, 'es', 'Jonas Hennes', 'Director general', '<div>Soy el director de una firma de bienes raíces de arquitectura. Tengo muchos proyectos en los que trabajo con artesanos, albañiles, pintores, carpinteros, plomeros, etc. Necesitaba tomar cursos prácticos de expertos para poder revisar su trabajo y asegurarme de que fuera de alta calidad, y esto es lo que encontrado en su maravillosa plataforma, lo que me ahorró una gran cantidad de tiempo, esfuerzo y dinero. Como resultado de la excelente experiencia, ahora me estoy preparando a mí ya mis empleados para tomar cursos de administración, mercadeo y administración de proyectos.</div>'),
(11, 4, 'ar', 'جوناس هينز', 'مدير شركة', '<div>انا مدير مكتب تشطيبات عقارية معمارية .لدي عمليات ومشروعات كثيرة أتعامل فيها مع حرفيين وعمال بناء وعمال دهانات ونجارين وسباكين وخلافه. ولكي استطيع مراجعة عملهم والتأكد من جودته كان لابد لي من دورات عملية في كافه تلك المهن من خبراء في هذه المهن وهو ما وجدته منصتكم الرائعة التي وفرت لي الكثير من الجهد والوقت والمال حيث اشتركت في كافة الدورات التي أريدها في كافه الفئات وتم كل ذلك بسهولة شديدة. كانت التجربة ممتازة وأنا الآن أحضر لاشتراكي في دورات الادارة والتسويق وادارة المشروعات أيضا لي وللموظفين لدي&nbsp;</div><div><br></div>'),
(16, 2, 'bn', 'হ্যারল্ড নিউম্যান', 'পেশাদার প্লাম্বার', '<p>40 বছর ধরে একজন প্লাম্বিং পেশাদার হিসাবে, আমি আমার কাজ পছন্দ করতাম, এবং আমার অন্য কোন জ্ঞান নেই। যেহেতু আমার বয়স 60 বছরের বেশি, আমার স্বাস্থ্য ততটা দক্ষ ছিল না যতটা হওয়া উচিত ছিল এবং আমি একাকীত্ব এবং শূন্যতায় এতটাই ভুগছিলাম যে আমাকে একজন সাইকোথেরাপিস্টের কাছে যেতে হয়েছিল। কেমেকাডেমির কথা শোনার পর, আমি ভাবলাম, \"কেন আমার অবসর সময় তরুণদের প্লাম্বিং পেশা শেখানোর জন্য ব্যয় করব না?\"। এটা আমার করা সেরা সিদ্ধান্ত ছিল. সত্যই, এটা আশ্চর্যজনক ছিল. আমার কোর্সের ফলস্বরূপ, আমি অনুভব করেছি যে আমার সম্প্রদায়ের এখনও আমাকে প্রয়োজন এবং আমার কাছে প্রস্তাব করার মূল্য আছে। আমাকে আমার অভিজ্ঞতা শেয়ার করার অনুমতি দেওয়ার জন্য এবং আমাকে আমার বিচ্ছিন্নতা থেকে বের করে আনার জন্য ধন্যবাদ</p>'),
(17, 2, 'zh', '哈罗德·纽曼', '专业水管工', '<p>作为一名 40 年的管道专业人士，我热爱我的工作，而且我没有其他知识。 因为我已经超过 60 岁，我的健康没有达到应有的水平，我感到孤独和空虚，以至于我不得不去看心理治疗师。 在听说了 kemecademy 之后，我想，“为什么不利用我的空闲时间来教年轻人水暖行业呢？”。 这是我做过的最好的决定。 老实说，这太棒了。 由于我的课程，我觉得我的社区仍然需要我，而且我可以提供价值。 感谢您让我分享我的经历并让我摆脱孤立</p>'),
(18, 2, 'fr', 'Harold Newmann', 'Plombier professionnel', '<p>En tant que professionnel de la plomberie depuis 40 ans, j\'adorais mon métier, et je n\'ai aucune autre connaissance. Parce que j\'avais plus de 60 ans, ma santé n\'était pas aussi efficace qu\'elle aurait dû l\'être, et je souffrais tellement de solitude et de vide que j\'ai dû consulter un psychothérapeute. Après avoir entendu parler de kemecademy, je me suis dit : \"Pourquoi ne pas passer mon temps libre à enseigner aux jeunes le métier de plombier ?\". C\'était la meilleure décision que j\'aie jamais prise. Honnêtement, c\'était incroyable. À la suite de mes cours, j\'ai senti que ma communauté avait encore besoin de moi et que j\'avais de la valeur à offrir. Merci de me permettre de partager mon expérience et de me sortir de mon isolement</p>'),
(19, 2, 'de', 'Harald Neumann', 'Professioneller Klempner', '<p>Ich bin seit 40 Jahren Klempner und habe meinen Job geliebt, und ich habe keine anderen Kenntnisse. Da ich älter als 60 war, war meine Gesundheit nicht so gut, wie sie hätte sein sollen, und ich litt so sehr unter Einsamkeit und Leere, dass ich einen Psychotherapeuten aufsuchen musste. Nachdem ich von kemecademy gehört hatte, dachte ich: \"Warum verbringe ich nicht meine Freizeit damit, jungen Menschen den Beruf des Klempners beizubringen?\". Es war die beste Entscheidung, die ich je getroffen habe. Ehrlich gesagt, es war unglaublich. Als Ergebnis meiner Kurse hatte ich das Gefühl, dass meine Gemeinde mich immer noch brauchte und dass ich etwas zu bieten hatte. Danke, dass du mir erlaubst, meine Erfahrungen zu teilen und mich aus meiner Isolation herausgeholt hast</p>'),
(20, 2, 'hi', 'हेरोल्ड न्यूमैन', 'पेशेवर प्लंबर', '<p>40 वर्षों से प्लंबिंग पेशेवर के रूप में, मुझे अपनी नौकरी से प्यार है, और मुझे कोई अन्य ज्ञान नहीं है। क्योंकि मैं 60 वर्ष से अधिक का था, मेरा स्वास्थ्य उतना कुशल नहीं था जितना होना चाहिए था, और मैं अकेलेपन और खालीपन से इतना पीड़ित था कि मुझे एक मनोचिकित्सक को देखना पड़ा। केमेकैडमी के बारे में सुनने के बाद, मैंने सोचा, \"क्यों न मैं अपना खाली समय युवाओं को प्लंबिंग का पेशा सिखाने में बिताऊँ?\"। यह मेरा अब तक का सबसे अच्छा फैसला था। ईमानदारी से कहूं तो यह अद्भुत था। मेरे पाठ्यक्रमों के परिणामस्वरूप, मुझे लगा कि मेरे समुदाय को अभी भी मेरी आवश्यकता है और मेरे पास पेशकश करने के लिए मूल्य है। मुझे अपना अनुभव साझा करने और मुझे अपने अलगाव से बाहर लाने की अनुमति देने के लिए धन्यवाद</p>'),
(21, 2, 'id', 'Harold Newman', 'Tukang Pipa Profesional', '<p>Sebagai seorang tukang ledeng profesional selama 40 tahun, saya menyukai pekerjaan saya, dan saya tidak memiliki pengetahuan lain. Karena saya berusia lebih dari 60 tahun, kesehatan saya tidak seefisien yang seharusnya, dan saya sangat menderita karena kesepian dan kehampaan sehingga saya harus menemui psikoterapis. Setelah mendengar tentang kemecademy, saya berpikir, \"Mengapa tidak menghabiskan waktu luang saya untuk mengajar anak-anak muda tentang profesi tukang ledeng?\". Itu adalah keputusan terbaik yang pernah saya buat. Sejujurnya, itu luar biasa. Sebagai hasil dari kursus saya, saya merasa komunitas saya masih membutuhkan saya dan saya memiliki nilai untuk ditawarkan. Terima kasih telah mengizinkan saya untuk berbagi pengalaman dan membawa saya keluar dari keterasingan saya</p>'),
(22, 2, 'it', 'Harold Newmann', 'Idraulico professionista', '<p>Come professionista idraulico da 40 anni, ho amato il mio lavoro e non ho altre conoscenze. Poiché avevo più di 60 anni, la mia salute non era efficiente come avrebbe dovuto essere e soffrivo così tanto di solitudine e vuoto che dovevo vedere uno psicoterapeuta. Dopo aver sentito parlare di kemecademy, ho pensato: \"Perché non passare il mio tempo libero insegnando ai giovani il mestiere di idraulico?\". È stata la decisione migliore che abbia mai preso. Onestamente, è stato fantastico. Come risultato dei miei corsi, sentivo che la mia comunità aveva ancora bisogno di me e che avevo valore da offrire. Grazie per avermi permesso di condividere la mia esperienza e avermi fatto uscire dal mio isolamento</p>'),
(23, 2, 'ja', 'ハロルド・ニューマン', 'プロの配管工', '<p>配管の専門家として 40 年間、私は自分の仕事が大好きで、それ以外の知識はありませんでした。 私は 60 歳を超えていたので、健康状態は本来あるべきほど効率的ではなく、孤独と虚無感に苦しみ、心理療法士に診てもらう必要がありました。 ケメカデミーの話を聞いて、「暇な時間を使って若い人たちに配管工を教えてみませんか？」と思いました。 今までで最高の決断でした。 正直、すごかったです。 コースを受講した結果、コミュニティは今でも私を必要としており、提供できる価値があると感じました。 私の経験を分かち合い、孤独から抜け出させてくれてありがとう</p>'),
(24, 2, 'ko', '해롤드 뉴먼', '전문 배관공', '<p>40년 동안 배관 전문가로서 저는 제 일을 사랑했고 다른 지식은 없었습니다. 60세가 넘었기 때문에 건강도 생각만큼 효율적이지 않았고, 심리치료사를 만나야 할 정도로 외로움과 공허감에 시달렸습니다. 케메카데미에 대해 듣고 나서 \"젊은이들에게 배관공이라는 직업을 가르치면서 자유 시간을 보내지 않겠습니까?\"라고 생각했습니다. 내가 내린 최고의 결정이었습니다. 솔직히 놀랍습니다. 과정을 마친 결과, 커뮤니티에 여전히 저를 필요로 하고 제가 제공할 가치가 있다고 느꼈습니다. 제 경험을 공유할 수 있게 해주시고 고립에서 벗어나게 해주셔서 감사합니다.</p>'),
(25, 2, 'ms', 'Harold Newman', 'Tukang Paip Profesional', '<p>Sebagai profesional paip selama 40 tahun, saya menyukai pekerjaan saya, dan saya tidak mempunyai pengetahuan lain. Kerana saya berumur lebih daripada 60 tahun, kesihatan saya tidak cekap seperti yang sepatutnya, dan saya mengalami kesunyian dan kekosongan sehingga saya terpaksa berjumpa pakar psikoterapi. Selepas mendengar tentang kemecademy, saya berfikir, \"Kenapa tidak menghabiskan masa lapang saya mengajar orang muda profesion paip?\". Ia adalah keputusan terbaik yang pernah saya buat. Secara jujur, ia sangat mengagumkan. Hasil daripada kursus saya, saya merasakan komuniti saya masih memerlukan saya dan saya mempunyai nilai untuk ditawarkan. Terima kasih kerana membenarkan saya berkongsi pengalaman saya dan membawa saya keluar dari pengasingan</p>'),
(26, 2, 'ru', 'Гарольд Ньюман', 'Профессиональный сантехник', '<p>Работая сантехником 40 лет, я любил свою работу, а других знаний у меня нет. Поскольку мне было за 60, мое здоровье было не таким крепким, как должно было быть, и я так страдала от одиночества и пустоты, что мне пришлось обратиться к психотерапевту. Услышав о кемекадемии, я подумал: «Почему бы не потратить свое свободное время на обучение молодежи профессии сантехника?». Это было лучшее решение, которое я когда-либо принимал. Честно говоря, это было потрясающе. В результате моих курсов я почувствовал, что мое сообщество по-прежнему нуждается во мне и что я могу предложить что-то ценное. Спасибо, что позволили мне поделиться своим опытом и вытащили меня из изоляции</p>'),
(27, 2, 'th', 'ฮาโรลด์ นิวแมน', 'ช่างประปามืออาชีพ', '<p>ในฐานะที่ฉันทำงานด้านประปามา 40 ปี ฉันรักงานของฉัน และไม่มีความรู้อื่นใดเลย เนื่องจากฉันอายุมากกว่า 60 ปี สุขภาพของฉันจึงไม่มีประสิทธิภาพเท่าที่ควร และฉันต้องทนทุกข์ทรมานจากความเหงาและความว่างเปล่าจนต้องไปพบนักจิตบำบัด หลังจากได้ยินเกี่ยวกับ kemecademy ฉันคิดว่า \"ทำไมไม่ใช้เวลาว่างของฉันไปสอนเยาวชนเกี่ยวกับอาชีพช่างประปา\" มันเป็นการตัดสินใจที่ดีที่สุดที่ฉันเคยทำมา พูดตามตรง มันน่าทึ่งมาก ผลจากหลักสูตรของฉัน ฉันรู้สึกว่าชุมชนของฉันยังต้องการฉันอยู่และฉันก็มีคุณค่าที่จะนำเสนอ ขอบคุณที่ให้ฉันแบ่งปันประสบการณ์และพาฉันออกจากความโดดเดี่ยว</p>'),
(28, 2, 'tr', 'Harold Newman', 'Profesyonel Tesisatçı', '<p>40 yıllık tesisatçı olarak işimi çok sevdim ve başka bilgim yok. 60 yaşından büyük olduğum için sağlığım olması gerektiği kadar verimli değildi ve yalnızlık ve boşluktan o kadar çok acı çektim ki bir psikoterapiste görünmek zorunda kaldım. Keme Akademi\'yi duyduktan sonra \"Boş zamanımı neden gençlere tesisatçılık mesleğini öğreterek geçirmeyeyim?\" diye düşündüm. Şimdiye kadar verdiğim en iyi karardı. Dürüst olmak gerekirse, harikaydı. Kurslarımın bir sonucu olarak, topluluğumun bana hala ihtiyacı olduğunu ve sunabileceğim bir değerim olduğunu hissettim. Deneyimlerimi paylaşmama izin verdiğin ve beni yalnızlığımdan çıkardığın için teşekkürler.</p>'),
(29, 2, 'ur', 'ہیرالڈ نیومین', 'پیشہ ور پلمبر', '<p>40 سالوں سے پلمبنگ پروفیشنل کے طور پر، مجھے اپنی نوکری پسند تھی، اور مجھے کوئی اور علم نہیں ہے۔ چونکہ میری عمر 60 سال سے زیادہ تھی، اس لیے میری صحت اتنی موثر نہیں تھی جتنی کہ ہونی چاہیے تھی، اور میں تنہائی اور خالی پن کا اس قدر شکار ہوا کہ مجھے ایک سائیکو تھراپسٹ کے پاس جانا پڑا۔ kemecademy کے بارے میں سننے کے بعد، میں نے سوچا، \"کیوں نہ اپنا فارغ وقت نوجوانوں کو پلمبنگ کا پیشہ سکھانے میں گزاروں؟\"۔ یہ میں نے اب تک کا بہترین فیصلہ کیا ہے۔ سچ میں، یہ حیرت انگیز تھا. اپنے کورسز کے نتیجے میں، میں نے محسوس کیا کہ میری کمیونٹی کو اب بھی میری ضرورت ہے اور میرے پاس پیشکش کرنے کی قدر ہے۔ مجھے اپنا تجربہ شیئر کرنے کی اجازت دینے اور مجھے اپنی تنہائی سے نکالنے کا شکریہ</p>'),
(30, 2, 'vi', 'Harold Newman', 'Thợ sửa ống nước chuyên nghiệp', '<p>Là một thợ sửa ống nước chuyên nghiệp trong 40 năm, tôi yêu công việc của mình và tôi không có kiến thức nào khác. Vì tôi đã ngoài 60, sức khỏe của tôi không còn hiệu quả như lẽ ra phải có, và tôi phải chịu đựng sự cô đơn và trống rỗng đến mức phải đến gặp bác sĩ tâm lý. Sau khi nghe đến kemecademy, tôi nghĩ: “Tại sao không dành thời gian rảnh của mình để dạy các bạn trẻ nghề sửa ống nước nhỉ?”. Đó là quyết định tốt nhất tôi từng đưa ra. Thành thật mà nói, nó thật tuyệt vời. Kết quả của các khóa học của tôi là tôi cảm thấy rằng cộng đồng của tôi vẫn cần tôi và tôi có giá trị để cống hiến. Cảm ơn vì đã cho phép tôi chia sẻ kinh nghiệm của mình và đưa tôi thoát khỏi sự cô lập</p>'),
(31, 3, 'bn', 'সানা মাগদি', 'মা', '<p>আমি যমজ সন্তানের মা। তাদের বয়স 15 বছর। আমি বিশ্বাস করি যে প্রত্যেক শিশুরই তার পেশা শেখা উচিত যাতে শিক্ষাগত এবং আর্থিক কারণে হস্তশিল্প বা রিয়েলস্টেট পেশা থেকে পেশীবহুল প্রচেষ্টার প্রয়োজন হয়। আমার প্রচেষ্টা সত্ত্বেও, আমি এমন একটি জায়গা খুঁজে পাইনি যেখানে আমার বাচ্চারা তাদের জন্য উপযুক্ত কোর্স নির্বাচন করতে পারে। যত তাড়াতাড়ি আমি Kemecademy খুঁজে পেয়েছি, আমি উত্তেজিত হয়েছিলাম কারণ আমি আমার এলাকার শত শত প্রশিক্ষক এবং শত শত কোর্সের মধ্যে বেছে নিতে পারি। আমার গবেষণা অনুসারে, কেমেকাডেমি একটি অনন্য পরিষেবা যা বৃত্তিমূলক প্রশিক্ষণের বিশ্বকে ইতিবাচকভাবে প্রভাবিত করবে।</p>'),
(32, 3, 'zh', '萨那马格迪', '母亲', '<p>我是双胞胎孩子的母亲。 他们15岁。 我相信，出于教育和经济原因，每个孩子都应该从手工艺品或房地产行业学习他需要大力努力的职业。 尽管我很努力，但我还是找不到一个地方让我的孩子选择适合他们的课程。 一找到 Kemecademy，我就很兴奋，因为我可以在我所在地区的数百个培训师和数百个课程中进行选择。 根据我的研究，Kemecademy 是一项独特的服务，将对职业培训领域产生积极影响。</p>'),
(33, 3, 'fr', 'Sanaa Magdy', 'Mère', '<p>Je suis mère de jumeaux. Ils ont 15 ans. Je crois que chaque enfant devrait apprendre son métier qui nécessite des efforts musculaires de l\'artisanat ou des métiers de l\'immobilier pour des raisons pédagogiques et financières. Malgré mes efforts, je n\'ai pas réussi à trouver un endroit où mes enfants pourraient choisir des cours qui leur convenaient. Dès que j\'ai trouvé Kemecademy, j\'étais excité parce que je pouvais choisir parmi des centaines de formateurs et des centaines de cours dans ma région. Selon mes recherches, Kemecademy est un service unique qui aura un impact positif sur le monde de la formation professionnelle.</p>'),
(34, 3, 'de', 'Sana Magdy', 'Mutter', '<p>Ich bin Mutter von Zwillingskindern. Sie sind 15 Jahre alt. Ich bin der Meinung, dass jedes Kind seinen Beruf erlernen sollte, der aus pädagogischen und finanziellen Gründen Muskelanstrengungen aus handwerklichen oder Immobilienberufen erfordert. Trotz meiner Bemühungen konnte ich keinen Ort finden, an dem meine Kinder Kurse auswählen konnten, die für sie geeignet waren. Als ich Kemecademy gefunden habe, war ich begeistert, weil ich aus Hunderten von Trainern und Hunderten von Kursen in meiner Nähe wählen konnte. Nach meinen Recherchen ist die Kemecademy ein einzigartiger Service, der die Welt der Berufsbildung positiv beeinflussen wird.</p>'),
(35, 3, 'hi', 'साना मैगी', 'मां', '<p>मैं जुड़वां बच्चों की मां हूं। वे 15 साल के हैं। मेरा मानना है कि हर बच्चे को अपना पेशा सीखना चाहिए, जिसमें शैक्षिक और वित्तीय कारणों से हस्तशिल्प या रियल एस्टेट व्यवसायों से मांसपेशियों के प्रयासों की आवश्यकता होती है। मेरे प्रयासों के बावजूद, मुझे ऐसी जगह नहीं मिली जहां मेरे बच्चे अपने लिए उपयुक्त पाठ्यक्रम का चयन कर सकें। जैसे ही मुझे केमेकैडी मिला, मैं उत्साहित हो गया क्योंकि मैं अपने क्षेत्र के सैकड़ों प्रशिक्षकों और सैकड़ों पाठ्यक्रमों में से चुन सकता था। मेरे शोध के अनुसार, केमेकैडमी एक अनूठी सेवा है जो व्यावसायिक प्रशिक्षण की दुनिया पर सकारात्मक प्रभाव डालेगी।</p>'),
(36, 3, 'id', 'Sanaa Magdy', 'Ibu', '<p>Saya seorang ibu dari anak kembar. Mereka berusia 15 tahun. Saya percaya bahwa setiap anak harus mempelajari profesinya yang membutuhkan usaha keras dari kerajinan tangan atau profesi realestate untuk alasan pendidikan dan keuangan. Terlepas dari upaya saya, saya tidak dapat menemukan tempat di mana anak-anak saya dapat memilih kursus yang sesuai untuk mereka. Begitu saya menemukan Kemecademy, saya sangat senang karena saya dapat memilih di antara ratusan Pelatih dan ratusan kursus di daerah saya. Menurut penelitian saya, Kemecademy adalah layanan unik yang akan berdampak positif bagi dunia pelatihan kejuruan.</p>'),
(37, 3, 'it', 'Sana Magdy', 'Madre', '<p>Sono madre di due gemelli. Hanno 15 anni. Credo che ogni bambino dovrebbe imparare la sua professione che ha bisogno di sforzi muscolari dalle professioni artigiane o immobiliari per motivi educativi e finanziari. Nonostante i miei sforzi, non sono riuscito a trovare un posto dove i miei figli potessero scegliere corsi adatti a loro. Appena ho scoperto Kemecademy, ero entusiasta perché potevo scegliere tra centinaia di Trainer e centinaia di corsi nella mia zona. Secondo la mia ricerca, Kemecademy è un servizio unico che avrà un impatto positivo sul mondo della formazione professionale.</p>'),
(38, 3, 'ja', 'サナ・マグディ', '母親', '<p>私は双子の子供の母親です。 彼らは15歳です。 私は、すべての子供が、教育的および経済的理由から、手工芸品または不動産の専門家から力を必要とする職業を学ぶべきだと信じています。 いくら頑張っても、子どもたちが自分に合ったコースを選択できる場所が見つかりませんでした。 Kemecademy を見つけるとすぐに、自分の地域の何百ものトレーナーと何百ものコースの中から選択できることに興奮しました。 私の調査によると、ケメカデミーは職業訓練の世界にプラスの影響を与えるユニークなサービスです。</p>'),
(39, 3, 'ko', '사나 마그디', '어머니', '<p>저는 쌍둥이 아이의 엄마입니다. 그들은 15세입니다. 나는 모든 아이들이 교육적 및 재정적 이유로 수공예 또는 부동산 직업에서 근력이 필요한 직업을 배워야 한다고 믿습니다. 내 노력에도 불구하고 나는 우리 아이들이 그들에게 적합한 과정을 선택할 수 있는 곳을 찾을 수 없었다. Kemecademy를 발견하자마자 저는 제 지역에 있는 수백 명의 트레이너와 수백 개의 코스 중에서 선택할 수 있다는 사실에 흥분했습니다. 내 연구에 따르면 Kemecademy는 직업 훈련의 세계에 긍정적인 영향을 미칠 독특한 서비스입니다.</p>'),
(40, 3, 'ms', 'Sanaa Magdy', 'ibu', '<p>Saya seorang ibu kepada anak kembar. Mereka berumur 15 tahun. Saya percaya bahawa setiap kanak-kanak harus mempelajari profesionnya yang memerlukan usaha otot daripada kraftangan atau profesion hartanah atas sebab pendidikan dan kewangan. Walaupun saya berusaha, saya tidak dapat mencari tempat di mana anak-anak saya boleh memilih kursus yang sesuai untuk mereka. Sebaik sahaja saya menemui Kemecademy, saya teruja kerana saya boleh memilih antara ratusan Jurulatih dan ratusan kursus di kawasan saya. Menurut kajian saya, Kemecademy adalah perkhidmatan unik yang akan memberi impak positif kepada dunia latihan vokasional.</p>'),
(41, 3, 'ru', 'Сана Магди', 'Мать', '<p>Я мать детей-двойняшек. Им 15 лет. Я считаю, что каждый ребенок должен освоить свою профессию, требующую мускульных усилий, от ремесел или профессий, связанных с недвижимостью, по образовательным и финансовым причинам. Несмотря на все мои усилия, мне не удалось найти место, где мои дети могли бы выбрать курсы, которые им подходят. Как только я нашел Kemecademy, я был взволнован, потому что я мог выбирать среди сотен тренеров и сотен курсов в моем районе. Согласно моим исследованиям, Kemecademy — это уникальный сервис, который положительно повлияет на мир профессионального обучения.</p>'),
(42, 3, 'th', 'ซาน่า แม็กดี้', 'แม่', '<p>ฉันเป็นแม่ของลูกแฝด พวกเขาอายุ 15 ปี ฉันเชื่อว่าเด็กทุกคนควรเรียนรู้อาชีพที่ต้องใช้ความพยายามของกล้ามเนื้อจากงานฝีมือหรืออาชีพอสังหาริมทรัพย์ด้วยเหตุผลทางการศึกษาและการเงิน แม้จะพยายามแล้ว แต่ก็ไม่สามารถหาสถานที่ที่ลูกๆ สามารถเลือกหลักสูตรที่เหมาะสมกับพวกเขาได้ ทันทีที่ฉันพบ Kemecademy ฉันรู้สึกตื่นเต้นเพราะฉันสามารถเลือกได้จากเทรนเนอร์หลายร้อยคนและหลักสูตรหลายร้อยหลักสูตรในพื้นที่ของฉัน จากการวิจัยของฉัน Kemecademy เป็นบริการพิเศษที่จะส่งผลดีต่อโลกของการฝึกอบรมสายอาชีพ</p>'),
(43, 3, 'tr', 'Sanaa Magdy', 'Anne', '<p>Ben ikiz çocuk annesiyim. 15 yaşındalar. Her çocuğun el işi ya da emlakçılık mesleğini eğitimsel ve ekonomik nedenlerle öğrenmesi gerektiğine inanıyorum. Uğraşmama rağmen çocuklarımın kendilerine uygun dersleri seçebilecekleri bir yer bulamadım. Kemecademy\'yi bulur bulmaz heyecanlandım çünkü alanımdaki yüzlerce Eğitmen ve yüzlerce kurs arasından seçim yapabiliyordum. Araştırmalarıma göre Kemecademy mesleki eğitim dünyasını olumlu yönde etkileyecek eşsiz bir hizmet.</p>'),
(44, 3, 'ur', 'ثناء مگدی', 'ماں', '<p>میں جڑواں بچوں کی ماں ہوں۔ ان کی عمریں 15 سال ہیں۔ میرا ماننا ہے کہ ہر بچے کو اپنا پیشہ سیکھنا چاہیے جس کے لیے تعلیمی اور مالی وجوہات کی بنا پر دستکاری یا رئیل اسٹیٹ کے پیشوں سے پٹھوں کی کوششوں کی ضرورت ہے۔ میری کوششوں کے باوجود، میں ایسی جگہ تلاش کرنے سے قاصر تھا جہاں میرے بچے ایسے کورسز کا انتخاب کر سکیں جو ان کے لیے موزوں ہوں۔ جیسے ہی مجھے Kemecademy ملا، میں پرجوش ہو گیا کیونکہ میں اپنے علاقے میں سینکڑوں ٹرینرز اور سینکڑوں کورسز میں سے انتخاب کر سکتا تھا۔ میری تحقیق کے مطابق Kemecademy ایک منفرد سروس ہے جو پیشہ ورانہ تربیت کی دنیا پر مثبت اثر ڈالے گی۔</p>'),
(45, 3, 'vi', 'Sanaa Magdy', 'Mẹ', '<p>Tôi là mẹ của hai đứa con sinh đôi. Họ 15 tuổi. Tôi tin rằng mọi đứa trẻ nên học nghề cần nỗ lực cơ bắp từ thủ công mỹ nghệ hoặc nghề bất động sản vì lý do giáo dục và tài chính. Bất chấp những nỗ lực của tôi, tôi không thể tìm được một nơi mà các con tôi có thể chọn các khóa học phù hợp với chúng. Ngay khi tôi tìm thấy Kemecademy, tôi đã rất phấn khích vì tôi có thể chọn trong số hàng trăm Giảng viên và hàng trăm khóa học trong khu vực của mình. Theo nghiên cứu của tôi, Kemecademy là một dịch vụ độc đáo sẽ tác động tích cực đến thế giới đào tạo nghề.</p>'),
(46, 4, 'bn', 'জোনাস হেনেস', 'পরিচালন অধিকর্তা', '<p>আমি একটি আর্কিটেকচারাল রিয়েল এস্টেট ফার্মের পরিচালক। আমার অনেক প্রকল্প আছে যেখানে আমি কারিগর, নির্মাণ শ্রমিক, চিত্রশিল্পী, ছুতোর, প্লাম্বার ইত্যাদির সাথে কাজ করি। তাদের কাজ পর্যালোচনা করার জন্য এবং এটি উচ্চ মানের ছিল তা নিশ্চিত করার জন্য আমাকে বিশেষজ্ঞদের কাছ থেকে ব্যবহারিক কোর্স নেওয়ার প্রয়োজন ছিল এবং আমি এটিই করি। আপনার দুর্দান্ত প্ল্যাটফর্মে পাওয়া গেছে, যা আমার অনেক সময়, প্রচেষ্টা এবং অর্থ বাঁচিয়েছে। চমৎকার অভিজ্ঞতার ফলস্বরূপ, আমি এখন নিজেকে এবং আমার কর্মচারীদের ব্যবস্থাপনা, বিপণন এবং প্রকল্প পরিচালনার কোর্স করার জন্য প্রস্তুত করছি।</p>'),
(47, 4, 'zh', '乔纳斯·亨内斯', '常务董事', '<p>我是一家建筑房地产公司的董事。 我有很多项目，我与工匠、建筑工人、油漆工、木匠、水管工等一起工作。我需要参加专家的实践课程，以审查他们的工作并确保其质量，这就是我的工作 在您出色的平台上找到的，这为我节省了大量时间、精力和金钱。 由于获得了出色的经验，我现在正在为自己和我的员工准备学习管理、市场营销和项目管理方面的课程。</p>'),
(48, 4, 'fr', 'Jonas Hennes', 'Directeur général', '<p>Je suis le directeur d\'une société immobilière architecturale. J\'ai de nombreux projets dans lesquels je travaille avec des artisans, des ouvriers du bâtiment, des peintres, des charpentiers, des plombiers, etc. J\'avais besoin de suivre des cours pratiques d\'experts afin d\'examiner leur travail et de s\'assurer qu\'il était de haute qualité, et c\'est ce que j\'ai trouvé sur votre merveilleuse plateforme, ce qui m\'a permis d\'économiser beaucoup de temps, d\'efforts et d\'argent. Grâce à cette excellente expérience, je me prépare maintenant, ainsi que mes employés, à suivre des cours de gestion, de marketing et de gestion de projet.</p>'),
(49, 4, 'de', 'Jonas Henne', 'Geschäftsführer', '<p>Ich bin der Direktor eines architektonischen Immobilienbüros. Ich habe viele Projekte, in denen ich mit Handwerkern, Bauarbeitern, Malern, Tischlern, Klempnern usw. zusammenarbeite. Ich musste praktische Kurse von Experten belegen, um ihre Arbeit zu überprüfen und sicherzustellen, dass sie von hoher Qualität ist, und das ist es, was ich getan habe auf Ihrer wunderbaren Plattform gefunden, die mir viel Zeit, Mühe und Geld gespart hat. Aufgrund der hervorragenden Erfahrungen bereite ich mich und meine Mitarbeiter nun auf Kurse in Management, Marketing und Projektmanagement vor.</p>'),
(50, 4, 'hi', 'जोनास हेन्स', 'प्रबंध निदेशक', '<p>मैं एक वास्तुशिल्प रियल एस्टेट फर्म का निदेशक हूं। मेरे पास कई परियोजनाएँ हैं जिनमें मैं शिल्पकारों, निर्माण श्रमिकों, चित्रकारों, बढ़ई, प्लंबर आदि के साथ काम करता हूँ। मुझे उनके काम की समीक्षा करने और यह सुनिश्चित करने के लिए कि यह उच्च गुणवत्ता का है, विशेषज्ञों से व्यावहारिक पाठ्यक्रम लेने की आवश्यकता थी, और यह वही है जो मैंने किया था। आपके अद्भुत मंच पर मिला, जिसने मुझे बहुत समय, प्रयास और पैसा बचाया। उत्कृष्ट अनुभव के परिणामस्वरूप, मैं अब खुद को और अपने कर्मचारियों को प्रबंधन, विपणन और परियोजना प्रबंधन में पाठ्यक्रम लेने के लिए तैयार कर रहा हूं।</p>'),
(51, 4, 'id', 'Jonas Hennes', 'Direktur pengatur', '<p>Saya adalah direktur sebuah firma real estat arsitektur. Saya memiliki banyak proyek di mana saya bekerja dengan pengrajin, pekerja konstruksi, pelukis, tukang kayu, tukang ledeng, dll. Saya perlu mengambil kursus praktis dari para ahli untuk meninjau pekerjaan mereka dan memastikan kualitasnya tinggi, dan inilah yang saya ditemukan di platform Anda yang luar biasa, yang menghemat banyak waktu, tenaga, dan uang saya. Sebagai hasil dari pengalaman yang sangat baik, saya sekarang mempersiapkan diri dan karyawan saya untuk mengambil kursus manajemen, pemasaran, dan manajemen proyek.</p>'),
(52, 4, 'it', 'Jonas Hennes', 'Consigliere delegato', '<p>Sono il direttore di una società immobiliare di architettura. Ho molti progetti in cui lavoro con artigiani, muratori, imbianchini, falegnami, idraulici, ecc. Avevo bisogno di seguire corsi pratici da esperti per rivedere il loro lavoro e assicurarmi che fosse di alta qualità, e questo è quello che ho trovato sulla tua meravigliosa piattaforma, che mi ha fatto risparmiare un sacco di tempo, fatica e denaro. Grazie all\'ottima esperienza, ora sto preparando me stesso ei miei dipendenti a seguire corsi di management, marketing e project management.</p>'),
(53, 4, 'ja', 'ジョナス・ヘネス', '取締役社長', '<p>私は建築不動産会社の取締役です。 私は職人、建設労働者、画家、大工、配管工などと一緒に仕事をする多くのプロジェクトを持っています。専門家の仕事を見直して高品質であることを確認するために、専門家から実践的なコースを受講する必要がありました。 あなたの素晴らしいプラットフォームで見つけたので、時間、労力、お金を大幅に節約できました。 素晴らしい経験の結果、私は今、私自身と従業員が管理、マーケティング、およびプロジェクト管理のコースを受講する準備をしています.</p>'),
(54, 4, 'ko', '조나스 헤네스', '매니 징 디렉터', '<p>저는 건축 부동산 회사의 이사입니다. 나는 장인, 건설 노동자, 화가, 목수, 배관공 등과 함께 일하는 많은 프로젝트를 가지고 있습니다. 그들의 작업을 검토하고 고품질인지 확인하기 위해 전문가로부터 실용적인 과정을 수강해야 했습니다. 귀하의 멋진 플랫폼에서 발견하여 많은 시간, 노력 및 비용을 절약했습니다. 탁월한 경험의 결과로 저는 이제 저와 제 직원들이 관리, 마케팅 및 프로젝트 관리 과정을 수강할 수 있도록 준비하고 있습니다.</p>'),
(55, 4, 'ms', 'Jonas Hennes', 'Pengarah Urusan', '<p>Saya pengarah firma hartanah seni bina. Saya mempunyai banyak projek di mana saya bekerja dengan tukang, pekerja binaan, pelukis, tukang kayu, tukang paip, dll. Saya perlu mengikuti kursus praktikal daripada pakar untuk menyemak kerja mereka dan memastikan ia berkualiti tinggi, dan inilah yang saya ditemui pada platform hebat anda, yang menjimatkan banyak masa, usaha dan wang saya. Hasil daripada pengalaman yang sangat baik, saya kini sedang mempersiapkan diri saya dan pekerja saya untuk mengikuti kursus dalam pengurusan, pemasaran dan pengurusan projek.</p>'),
(56, 4, 'ru', 'Йонас Хеннес', 'Управляющий', '<p>Я директор архитектурной фирмы по недвижимости. У меня много проектов, в которых я работаю с мастерами, строителями, малярами, плотниками, сантехниками и т. д. Мне нужно было пройти практические курсы у специалистов, чтобы проверить их работу и убедиться, что она качественная, и это то, что я нашел на вашей замечательной платформе, что сэкономило мне много времени, усилий и денег. В результате отличного опыта я сейчас готовлю себя и своих сотрудников к прохождению курсов по менеджменту, маркетингу и управлению проектами.</p>'),
(57, 4, 'th', 'โยนาส เฮนเนส', 'กรรมการผู้จัดการ', '<p>ฉันเป็นผู้อำนวยการบริษัทอสังหาริมทรัพย์ด้านสถาปัตยกรรม ฉันมีโครงการมากมายที่ฉันทำงานร่วมกับช่างฝีมือ คนงานก่อสร้าง ช่างทาสี ช่างไม้ ช่างประปา ฯลฯ ฉันจำเป็นต้องเรียนหลักสูตรภาคปฏิบัติจากผู้เชี่ยวชาญเพื่อทบทวนงานของพวกเขาและให้แน่ใจว่างานนั้นมีคุณภาพสูง และนี่คือสิ่งที่ฉัน พบได้บนแพลตฟอร์มที่ยอดเยี่ยมของคุณ ซึ่งช่วยฉันประหยัดเวลา ความพยายาม และเงินได้อย่างมาก จากประสบการณ์ที่เป็นเลิศ ตอนนี้ฉันกำลังเตรียมตัวให้ตัวเองและพนักงานของฉันเรียนหลักสูตรการจัดการ การตลาด และการจัดการโครงการ</p>'),
(58, 4, 'tr', 'Jonas Hennes', 'Genel müdür', '<p>Bir mimari emlak firmasının yöneticisiyim. Ustalarla, inşaat işçileriyle, boyacılarla, marangozlarla, tesisatçılarla vs. çalıştığım birçok projem var. Yaptıkları işleri gözden geçirmek ve kaliteli olduğundan emin olmak için uzmanlardan uygulamalı dersler almam gerekiyordu ve ben de bunu yaptım. harika platformunuzda buldum, bu da bana çok fazla zaman, çaba ve para kazandırdı. Mükemmel deneyimin bir sonucu olarak, şimdi kendimi ve çalışanlarımı yönetim, pazarlama ve proje yönetimi dersleri almaya hazırlıyorum.</p>'),
(59, 4, 'ur', 'جوناس ہینس', 'منیجنگ ڈائریکٹر', '<p>میں ایک آرکیٹیکچرل ریئل اسٹیٹ فرم کا ڈائریکٹر ہوں۔ میرے پاس بہت سے منصوبے ہیں جن میں میں کاریگروں، تعمیراتی کارکنوں، پینٹروں، بڑھئیوں، پلمبروں وغیرہ کے ساتھ کام کرتا ہوں۔ مجھے ماہرین سے عملی کورسز لینے کی ضرورت تھی تاکہ ان کے کام کا جائزہ لیا جا سکے اور اس بات کو یقینی بنایا جا سکے کہ یہ اعلیٰ معیار کا ہے، اور میں یہی کرتا ہوں۔ آپ کے شاندار پلیٹ فارم پر پایا، جس نے میرا بہت وقت، محنت اور پیسہ بچایا۔ بہترین تجربے کے نتیجے میں، میں اب خود کو اور اپنے ملازمین کو مینجمنٹ، مارکیٹنگ، اور پراجیکٹ مینجمنٹ کے کورسز لینے کے لیے تیار کر رہا ہوں۔</p>'),
(60, 4, 'vi', 'Jonas Hennes', 'Giám đốc điều hành', '<p>Tôi là giám đốc một công ty bất động sản kiến trúc. Tôi có nhiều dự án làm việc với thợ thủ công, công nhân xây dựng, họa sĩ, thợ mộc, thợ sửa ống nước, v.v. Tôi cần tham gia các khóa học thực tế từ các chuyên gia để xem xét công việc của họ và đảm bảo rằng nó có chất lượng cao, và đây là điều tôi được tìm thấy trên nền tảng tuyệt vời của bạn, giúp tôi tiết kiệm rất nhiều thời gian, công sức và tiền bạc. Nhờ trải nghiệm tuyệt vời, tôi hiện đang chuẩn bị cho bản thân và nhân viên của mình tham gia các khóa học về quản lý, tiếp thị và quản lý dự án.</p>');

