 flex: 1 1 auto;\"><div id=\"mmt-biacdsid-f2ic-jitb-kmil-ictoamttthtc.13-cls2\" style=\"display: table; margin-right: auto; margin-left: auto;\"><div id=\"mmt-biacdsid-f2ic-jitb-kmil-ictoamttthtc.13-cls1\" style=\"display: flex; align-items: center; justify-content: center; background-color: rgba(233, 233, 233, 0.5); padding: 10px; min-width: 320px !important; min-height: 250px !important; box-sizing: content-box !important;\"><div id=\"mmt-biacdsid-f2ic-jitb-kmil-ictoamttthtc.13-ad\" data-google-query-id=\"CI7w-ZL_-f4CFYkPBgAdZ50GWA\"><div id=\"google_ads_iframe_/20842576,22874681548/JF002M/JF002M-DDL.M_0__container__\" style=\"border: 0pt none; width: 300px; height: 0px;\"></div></div></div></div></div><div id=\"mmt-biacdsid-f2ic-jitb-kmil-ictoamttthtc.14\" class=\"mmt-primary mmt-flight\" style=\"margin-bottom: 10px !important; flex: 1 1 auto;\"><div id=\"mmt-biacdsid-f2ic-jitb-kmil-ictoamttthtc.14-cls2\" style=\"display: table; margin-right: auto; margin-left: auto;\"><div id=\"mmt-biacdsid-f2ic-jitb-kmil-ictoamttthtc.14-cls1\" style=\"display: flex; align-items: center; justify-content: center; background-color: rgba(233, 233, 233, 0.5); padding: 10px; min-width: 320px !important; min-height: 250px !important; box-sizing: content-box !important;\"><div id=\"mmt-biacdsid-f2ic-jitb-kmil-ictoamttthtc.14-ad\" data-google-query-id=\"CJy0-pL_-f4CFQq91QodJXwJFg\"><div id=\"google_ads_iframe_/20842576,22874681548/JF002M/JF002M-DDL.N_0__container__\" style=\"border: 0pt none; width: 300px; height: 0px;\"></div></div></div></div></div></div><h2 class=\"wsite-content-title\" style=\"overflow-wrap: break-word; margin-right: auto; margin-bottom: 1em; margin-left: auto; border: 0px; text-align: justify; font-size: 15px !important; line-height: 30px !important; font-weight: 400 !important; font-family: Lato !important; color: rgb(80, 141, 36) !important;\"><font size=\"5\">Tape measure</font><br></h2><div class=\"paragraph\" style=\"overflow-wrap: break-word; margin-right: au