INSERT INTO `users` (`id`, `full_name`, `role_name`, `role_id`, `organ_id`, `mobile`, `email`, `bio`, `password`, `google_id`, `facebook_id`, `remember_token`, `logged_count`, `verified`, `financial_approval`, `installment_approval`, `enable_installments`, `disable_cashback`, `enable_registration_bonus`, `registration_bonus_amount`, `avatar`, `avatar_settings`, `cover_img`, `headline`, `about`, `address`, `country_id`, `province_id`, `city_id`, `district_id`, `location`, `level_of_training`, `meeting_type`, `status`, `access_content`, `enable_ai_content`, `language`, `currency`, `timezone`, `newsletter`, `public_message`, `identity_scan`, `certificate`, `commission`, `affiliate`, `can_create_store`, `ban`, `ban_start_at`, `ban_end_at`, `offline`, `offline_message`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'Admin', 'admin', 2, NULL, '00000000', 'admin@kemecademy.com', 'Senior software developer', '$2a$12$76k3Sm3Cd5hPATsrqd3JyOm/4.UJFAGOhslzW5mguxc.kVAx3d0NW', NULL, NULL, 'FcOQ4PndfuJo9HEV1KO7yVQe97ldgw40Libi3NjgAGjMwR3T8wjnOuHc6bex', 3, 1, 0, 0, 1, 0, 0, NULL, '/store/1/Logo-icons/favicon.png', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'all', 'active', 1, 0, 'VI', 'USD', 'America/New_York', 0, 0, NULL, NULL, NULL, 1, 0, 0, NULL, NULL, 0, NULL, 1597826952, 1597826952, NULL),
(3, 'Hanh Kong', 'teacher', 4, 864, '+12085141324', 'hanhkong@gmail.com', 'Plumbing like no other', '$2y$10$cvfO8sXAf3K3IdEjF6iRneBbP68fNx2SRYw942uzTsQomxAzkpCVO', NULL, NULL, '28oeg51M8qUs6bG6oBX0i8hzLmLG4ikSXQtIYaumrzg6wv3MKfqQwuCNFwX3', 1, 1, 1, 0, 1, 0, 0, NULL, '/store/1/posts/plumber1.png', NULL, '/store/1/posts/plumber2.jpg', NULL, 'Hanh Kong is a highly skilled and experienced professional plumbing trainer with a passion for sharing her expertise with aspiring plumbers. With over 20 years of practical experience in the plumbing industry, Hanh has become a trusted authority in the field.\r\n\r\nThroughout her career, Hanh has worked on a wide range of plumbing projects, including residential, commercial, and industrial installations. Her in-depth knowledge of plumbing systems, codes, and regulations has allowed her to deliver exceptional results while ensuring compliance with industry standards.\r\n\r\nRecognized for her ability to simplify complex concepts, Hanh has developed a reputation for being an effective and engaging trainer. She has a natural talent for breaking down technical information into easily understandable terms, making her training sessions accessible to learners of all skill levels.\r\n\r\nAs a plumbing trainer, Hanh is dedicated to empowering the next generation of plumbers with the necessary skills and knowledge to succeed in the industry. She takes a hands-on approach to training, combining theoretical instruction with practical exercises to provide a well-rounded learning experience.\r\n\r\nHanh\'s training programs cover a wide range of topics, including plumbing system design, pipefitting, fixture installation, troubleshooting, and repair techniques. Her curriculum incorporates the latest advancements in plumbing technology, emphasizing the importance of sustainability and energy efficiency in plumbing practices.\r\n\r\nHanh\'s passion for teaching extends beyond the classroom. She actively engages with her students, providing mentorship and guidance to help them navigate the challenges and opportunities within the plumbing industry. Her commitment to their success is evident in the positive feedback and accomplishments of her past trainees.\r\n\r\nIn addition to her role as a trainer, Hanh is involved in professional organizations and regularly participates in industry conferences and workshops. This enables her to stay up-to-date with the latest trends, techniques, and regulations, ensuring that her training programs remain relevant and comprehensive.\r\n\r\nOutside of her professional endeavors, Hanh enjoys spending time with her family and pursuing outdoor activities. She believes in giving back to the community and actively volunteers in local initiatives aimed at promoting plumbing education and awareness.\r\n\r\nWith Hanh as their trainer, aspiring plumbers can expect to receive top-notch instruction, practical insights, and the confidence to excel in their plumbing careers. Her dedication to imparting knowledge and fostering a supportive learning environment has made her an invaluable resource in the field of plumbing training.', '638153, Tamil Nadu, Modakkurichi, Elumathur', 20, 33, 34, 42, 0x000000000101000000c36b207dbda43840180620262a544740, b'110', 'all', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, '/store/3/passport.jpg', '', NULL, 1, 1, 0, NULL, NULL, 1, 'I will not be available for 2 weeks until  end of January due to a business trip.', 1597826952, 1597826952, NULL),
(4, 'Plumbing Academy', 'organization', 3, NULL, '+441632960079', 'plumbing@gmail.com', 'Plumbing like no oother', '$2y$10$NPgvpOF52CHJuSKbh9gG8.7IvjjFd0HklLy5elWySZ58m.9IHpM2K', NULL, NULL, 'HVMcrvVIvbrAWoMqj0keYcuCqkuVNZ5SumTNTlEY510zC373P6VQXFs6ZNN4', 0, 1, 0, 0, 1, 0, 0, NULL, '/store/1/posts/plu1.png', NULL, '/store/1/posts/pl1.jpeg', NULL, 'The Plumbing Academy is a leading institution dedicated to providing comprehensive and industry-focused training in the field of plumbing. With a commitment to excellence and a passion for shaping the next generation of plumbers, the academy has become a renowned center of learning under the visionary leadership of its founder, Mark Johnson.\r\n\r\nMark Johnson, an experienced plumbing professional with over 25 years of practical experience, recognized the need for a specialized training institution that could bridge the gap between theoretical knowledge and practical skills in the plumbing industry. With this vision in mind, he established the Plumbing Academy, combining his expertise and passion for teaching to create a transformative learning environment.\r\n\r\nAt the Plumbing Academy, students benefit from Mark\'s extensive knowledge and his ability to effectively convey complex plumbing concepts in a clear and engaging manner. With a strong emphasis on hands-on training, the academy provides a state-of-the-art facility equipped with modern plumbing tools and materials, allowing students to develop practical skills that are directly applicable to real-world plumbing scenarios.\r\n\r\nUnder Mark\'s guidance, the Plumbing Academy offers a comprehensive curriculum covering a wide range of plumbing topics, including plumbing system design, pipe installation, drainage systems, water supply, fixture installation, and repair techniques. The academy also places a strong emphasis on safety protocols, industry regulations, and environmental sustainability, ensuring that students are equipped with a well-rounded understanding of the plumbing profession.\r\n\r\nIn addition to the core curriculum, the Plumbing Academy fosters a supportive and collaborative learning environment. Mark and his team of experienced instructors are dedicated to providing individual attention and mentorship to each student, tailoring the training to their specific needs and goals. This personalized approach allows students to develop confidence, problem-solving abilities, and a strong work ethic that will serve them well throughout their plumbing careers.\r\n\r\nThe Plumbing Academy\'s commitment to excellence extends beyond graduation. The academy maintains strong industry connections and partnerships, providing students with access to internships, apprenticeship programs, and job placement assistance. This ensures that graduates are well-prepared to enter the workforce and contribute to the plumbing industry with their acquired skills and knowledge.\r\n\r\nThrough its unwavering dedication to providing high-quality training, the Plumbing Academy has earned a stellar reputation for producing skilled and competent plumbers. Graduates of the academy are sought after by employers and clients alike, knowing that they have received top-notch education and training from a trusted institution.\r\n\r\nAs the Plumbing Academy continues to grow and evolve, Mark Johnson remains committed to maintaining the academy\'s reputation as a center of excellence in plumbing education. With a focus on innovation, continuous improvement, and a passion for empowering individuals, the Plumbing Academy is poised to shape the future of the plumbing industry by nurturing the talents of aspiring plumbers and equipping them with the skills they need to thrive.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'all', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, NULL, NULL, NULL, 1, 1, 0, NULL, NULL, 0, NULL, 1597826952, 1597826952, NULL),
(863, 'Owosso', 'organization', 3, NULL, '+12025550198', 'owosso@info.com', 'Chemical Engineering Institute', '$2y$10$NPgvpOF52CHJuSKbh9gG8.7IvjjFd0HklLy5elWySZ58m.9IHpM2K', NULL, NULL, NULL, 0, 0, 0, 0, 1, 0, 0, NULL, '/store/863/avatar/617a5000eb040.png', NULL, '/store/863/2.png', NULL, 'Dear students,\r\n\r\nWR Training is a group of professional engineers from various disciplines (chemical, petrochemical, mechanical, electrical…) providing academic and industrial online courses.\r\n\r\nWhether you’re trying to learn and discover a new scientific or engineering topic from scratch, or want to refresh your memory on something you’ve learnt in the past, you’ve come to the right place.\r\n\r\nWR Training exists to help you succeed in your academic and professional life. Our goal is to spread the knowledge and promote science.\r\n\r\nThe courses, you are about to enroll in, were undertaken to give you a clear view of scientific and engineering topics through detailed examples using hands on demo and provide numerous problems with their solutions. You can also use these courses as a review for taking exams or as a vehicle for self-instruction.\r\n\r\nOur training methodology was designed to enable individual self paced e-learning.\r\n\r\nEach course has been undertaken to teach a specific skill.\r\n\r\nOur courses can be watched 24/7 wherever you are. You can also view them on mobile devices with the Udemy mobile app.\r\n\r\nWe are active online instructors and we will be here for you every step of the way. If you have questions about the course content, you can always post your questions or send us a private message. It will be our pleasure to provide assistance and answer your questions.\r\n\r\nSo with no further ado, go ahead, select the course suitable for you, click the enroll button and we\'ll see you in the first section !\r\n\r\nWR Training\r\n\r\nSpread the wings of your knowledge', NULL, 17, 28, 30, 37, 0x0000000001010000006656cabeb2f73240a691c50fda345240, b'110', 'online', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, NULL, NULL, NULL, 1, 0, 0, NULL, NULL, 0, NULL, 1604509713, NULL, NULL),
(864, 'Tiling Institute', 'organization', 3, NULL, '+12025550131', 'affogato@yahoo.com', 'Learn Creative Skills', '$2y$10$NPgvpOF52CHJuSKbh9gG8.7IvjjFd0HklLy5elWySZ58m.9IHpM2K', NULL, NULL, NULL, 0, 1, 0, 0, 1, 0, 0, NULL, '/store/864/avatar/617a5011ca3ba.png', NULL, '/store/864/20.jpg', NULL, 'Learn creative skills, from absolute beginner to advanced mastery. \r\n\r\nVideo School exists to help you succeed in life. Each course has been hand-tailored to teach a specific skill from photography and video to art, design and business.\r\n\r\nWhether you’re trying to learn a new skill from scratch, or want to refresh your memory on something you’ve learned in the past, you’ve come to the right place.\r\n\r\nEducation makes the world a better place. Make your world better with new skills!\r\n\r\nOur courses can be watched 24/7 wherever you are. Most are fully downloadable so you can take them with you.\r\n\r\nAll courses have a 30-day money-back guarantee so that you can check it out, make sure it’s the right course for you, and get a refund if it’s not!', NULL, 19, 61, 62, 65, 0x000000000101000000983696ed17262140f870c75749123040, b'100', 'all', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, NULL, NULL, NULL, 1, 1, 0, NULL, NULL, 0, NULL, 1604509713, NULL, NULL),
(867, 'Electricity group', 'organization', 3, NULL, '+12025550151', 'organization@demo.com', 'Building Better Professionals in Electricity', '$2y$10$W0.rfZgYCWGr/rOSrGrGg.Nnm6xBVdR3FYjJiXqiq6LZdx2Ds.aXq', NULL, NULL, 'BWflmtylS4Tli2iNjXU1uauLyg3OkvqqMJXK3ZBgugWems9IrTpI62QnMOxA', 0, 1, 1, 0, 1, 0, 0, NULL, '/store/1/posts/ele0.png', NULL, '/store/1/posts/ele1.jpg', NULL, 'The Light Moon Academy was created by Tim Buchalka, a software developer with 35 years experience, who is also an instructor on Udemy, with over 1.22M+ students in his courses on Java, Python, Android, C#  and the Spring framework. \r\n\r\nThe Academy’s goal in the next three years, is to teach one million people to learn how to program.\r\n\r\nApart from Tim’s own courses, which are all available here, we are working with the very best teachers, creating courses to teach the essential skills required by developers, at all levels.\r\n\r\nOne other important philosophy is that our courses are taught by real professionals; software developers with real and substantial experience in the industry, who are also great teachers.  All our instructors are experienced, software developers!\r\n\r\nOur team is busy creating new courses right now.\r\n\r\nWhether you are a beginner, looking to learn how to program for the very first time, or to brush up on your existing skills, or to learn new languages and frameworks, the Academy has you covered.', 'Massachusetts, West Roxbury, 3979 Smith Street', 16, 21, 67, 68, 0x000000000101000000b4c5c332820e4840b73e0bfa1c52fbbf, b'110', 'all', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, '/store/867/passport.jpg', '', NULL, 1, 1, 0, NULL, NULL, 0, NULL, 1604509713, NULL, NULL),
(868, 'Perfect Handymen', 'organization', 3, NULL, '+441632960582', 'perfecthandymen@info.com', 'Perfect Handymen Organization', '$2y$10$NPgvpOF52CHJuSKbh9gG8.7IvjjFd0HklLy5elWySZ58m.9IHpM2K', NULL, NULL, NULL, 0, 1, 0, 0, 1, 0, 0, NULL, '/store/1/posts/00.png', NULL, '/store/1/posts/001.jpg', NULL, 'Perfect Handymen Organization is a reputable institution dedicated to training and equipping handymen with the skills and knowledge necessary to excel in their craft. Led by a team of experienced professionals, the organization has become a trusted authority in the handyman industry.\r\n\r\nAt the helm of Perfect Handymen Organization is Alex Turner, a seasoned handyman with over 20 years of practical experience. Recognizing the need for comprehensive training programs and a standardized approach to handyman services, Alex founded the organization with a mission to empower handymen and elevate the quality of service in the industry.\r\n\r\nUnder Alex\'s leadership, Perfect Handymen Organization offers a structured curriculum that covers a wide range of handyman skills, including carpentry, plumbing, electrical work, painting, tiling, and general home repairs. The training programs combine theoretical knowledge with practical hands-on exercises, ensuring that handymen develop a well-rounded skill set and the ability to tackle diverse projects with confidence.\r\n\r\nIn addition to technical skills, Perfect Handymen Organization emphasizes the importance of professionalism, customer service, and business management. Handymen undergo training in effective communication, time management, client relations, and pricing strategies, enabling them to deliver exceptional service and build successful and sustainable handyman businesses.\r\n\r\nThe organization prides itself on its state-of-the-art training facilities, equipped with modern tools and materials to simulate real-world scenarios. The instructors at Perfect Handymen Organization are experienced professionals in their respective fields, providing expert guidance and mentorship to students throughout their training journey.\r\n\r\nPerfect Handymen Organization is committed to staying at the forefront of industry trends and advancements. The organization regularly updates its curriculum to reflect the latest technologies, best practices, and safety protocols in the handyman industry. This ensures that handymen trained by Perfect Handymen Organization are equipped with the most up-to-date knowledge and techniques.\r\n\r\nBeyond training, Perfect Handymen Organization fosters a strong sense of community among its graduates. Alumni have access to ongoing support, networking opportunities, and continuing education resources. The organization also offers assistance with job placement and business development, helping handymen kick-start their careers and establish a strong presence in the industry.\r\n\r\nWith a commitment to excellence, professionalism, and continuous improvement, Perfect Handymen Organization has gained a reputation for producing highly skilled and reliable handymen. Clients and employers recognize the organization\'s graduates for their exceptional craftsmanship, attention to detail, and commitment to customer satisfaction.\r\n\r\nThrough its dedication to providing top-quality training and support, Perfect Handymen Organization is reshaping the handyman industry by raising the bar for service quality and professionalism. Aspiring handymen who undergo training with the organization can be confident in their abilities to deliver top-notch service and make a positive impact in the field of handyman services.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'all', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, NULL, NULL, NULL, 1, 1, 0, NULL, NULL, 0, NULL, 1604509713, NULL, NULL),
(870, 'Alexander Grant', 'teacher', 4, 863, '+12025550188', 'marques.torp@hotmail.com', 'Architecture is my passion', '$2y$10$nUVsk1Q/XfPTlY6eT1seUeYcqTxRUqy6aikC341.urx8kQVM/cbRe', NULL, NULL, 'fICSOk0p4f5wFMFZN3hx1Z1sBfKE4xC8jjUrDBmEcIRkQOuWYYJN9vWUb1s1', 0, 1, 1, 0, 1, 0, 0, NULL, '/store/1/posts/aarchetict.png', NULL, '/store/1/posts/aarch2.png', NULL, 'Alexander Grant is a highly accomplished and renowned trainer in the field of architecture, providing comprehensive guidance and expertise to aspiring architects and seasoned professionals alike. With an illustrious career spanning over three decades, Alexander is recognized for his exceptional knowledge, creative flair, and commitment to architectural excellence.\r\n\r\nHaving worked on a diverse range of architectural projects worldwide, Alexander brings a wealth of practical experience to his training programs. His expertise encompasses various architectural styles, design principles, construction techniques, and project management methodologies.\r\n\r\nAs a trainer, Alexander is dedicated to nurturing the next generation of architects and empowering them with the skills and insights necessary to succeed in this competitive industry. His training sessions are carefully curated to cover a wide spectrum of topics, including architectural design fundamentals, 3D modeling, sustainable architecture, building codes and regulations, and the integration of technology in architectural workflows.\r\n\r\nAlexander\'s training style is characterized by his ability to blend theory and practice seamlessly. He employs interactive workshops, hands-on exercises, and real-world case studies to ensure participants gain practical experience and develop critical thinking skills essential for solving architectural challenges. His engaging teaching methods create a collaborative and inspiring environment that fosters creativity and innovation.\r\n\r\nBeyond his training endeavors, Alexander has established himself as a prominent architect and design consultant, having successfully completed numerous high-profile projects. His portfolio showcases a diverse range of architectural achievements, including residential complexes, commercial spaces, cultural institutions, and urban redevelopment initiatives.\r\n\r\nAlexander\'s passion for architecture extends beyond the aesthetics and functionality of buildings. He is a strong advocate for sustainable design practices, incorporating environmentally friendly solutions into his projects. Through his training programs, he instills in participants a deep understanding of the importance of sustainable design principles and encourages them to embrace responsible architecture for a better future.\r\n\r\nWhether you are an aspiring architect looking to build a strong foundation or an experienced professional seeking to refine your skills, Alexander Grant\'s training programs are designed to equip you with the knowledge, creativity, and technical expertise required to excel in the ever-evolving field of architecture. Join his transformative sessions and embark on a journey towards architectural mastery under the guidance of a true visionary.', NULL, 16, 22, 23, 26, 0x000000000101000000b2ea5bb7216d4840098c262b63310340, b'100', 'all', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, NULL, NULL, NULL, 1, 0, 0, NULL, NULL, 0, NULL, 1604509713, NULL, NULL),
(923, 'Ahmed Zayed', 'teacher', 4, 867, '+61498970158', 'ahmedzayed@yahoo.com', 'Professional carpenter trainer', '$2y$10$mviBMNi7i/bdXbw8lHHOu.k61PeIA1IanNd2ynIlOtDQUu8IwbzbS', NULL, NULL, 'WqxvUU0C5VE2PHK1gjx6jmdFkXdUSiEg4wOYb0nZFhYnY4xUtk3TN1zHcuVo', 1, 1, 0, 0, 1, 0, 0, NULL, '/store/1/posts/carp1.png', NULL, '/store/1/posts/carp2.png', NULL, 'Ahmed Zayed is a seasoned professional carpenter with over 15 years of experience in the construction industry. Known for his exceptional craftsmanship and attention to detail, Ahmed has established a reputation for delivering high-quality woodworking projects.\r\n\r\nThroughout his career, Ahmed has honed his skills in various aspects of carpentry, including framing, finish work, cabinetry, and furniture making. His expertise extends to both residential and commercial projects, where he has successfully completed renovations, remodels, and new construction ventures.\r\n\r\nWith a deep passion for his craft, Ahmed takes pride in transforming raw materials into functional and visually appealing structures. He combines his technical expertise with a keen eye for design, ensuring that every project showcases a seamless blend of aesthetics and functionality.\r\n\r\nAs a professional carpenter, Ahmed possesses a comprehensive understanding of construction principles and industry best practices. He stays up-to-date with the latest trends and advancements in carpentry techniques, tools, and materials, allowing him to deliver innovative and sustainable solutions to his clients.\r\n\r\nAhmed\'s dedication to his craft goes beyond the workshop. He values open communication and collaboration with clients, architects, and other professionals involved in the project. By actively listening to their needs and preferences, he ensures that every project is tailored to their vision while offering expert guidance and recommendations.\r\n\r\nWhether working on custom-built furniture, intricate trim installations, or large-scale construction projects, Ahmed\'s commitment to excellence shines through. His ability to meet deadlines, manage resources efficiently, and maintain a clean and organized workspace has earned him the trust and loyalty of his clients.\r\n\r\nIn addition to his hands-on experience, Ahmed holds certifications in carpentry and continually seeks opportunities for professional development. He believes in fostering a positive and supportive work environment and enjoys mentoring and sharing his knowledge with aspiring carpenters.\r\n\r\nWhen Ahmed is not immersed in the world of woodworking, he enjoys exploring the outdoors, hiking, and spending quality time with his family.', '106 Ben Street', 18, 46, 50, 57, NULL, NULL, 'all', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, NULL, NULL, NULL, 1, 1, 0, NULL, NULL, 0, NULL, 1604509713, NULL, NULL),
(929, 'Sophia Reynolds', 'teacher', 4, 868, '+12025550148', 'kate.williams.dev@yahoo.com', 'Real estate management trainer', '$2y$10$A.nll8bKsxa5ym2joEQetu5eojKIZnNTG3ht7ot1hn4nrW8w5G/wa', NULL, NULL, 'iTS5AUuMQzlLJHmFjXXOrvP8GWJIaCER9LMuKRmz8r3UsP36fWH2gGiT88IY', 0, 1, 0, 0, 1, 0, 0, NULL, '/store/929/avatar/617a4f5d834c8.png', '{\"color\":\"FFFFFF\",\"background\":\"8e24aa\"}', '/store/929/15.jpg', NULL, 'Sophia Reynolds is a highly regarded trainer specializing in real estate management, with a wealth of expertise and a track record of success in the industry. With over 20 years of experience, Sophia has become a trusted resource for professionals seeking to excel in the dynamic field of real estate.\r\n\r\nThroughout her career, Sophia has worked in various capacities, including property management, asset management, and portfolio optimization. Her diverse background has provided her with comprehensive knowledge of the entire real estate lifecycle, from acquisition and development to leasing and operations.\r\n\r\nAs a trainer, Sophia is known for her engaging and informative sessions that empower participants with the tools and strategies needed to navigate the complex world of real estate management. Her training programs cover a wide range of topics, including property valuation, financial analysis, lease negotiations, tenant relations, risk management, and regulatory compliance.\r\n\r\nSophia\'s approach is practical and results-oriented, focusing on real-world scenarios and best practices. Through interactive exercises, case studies, and group discussions, she ensures that participants not only understand the theoretical concepts but also gain valuable insights into effective implementation.\r\n\r\nSophia\'s training style is characterized by her ability to break down complex concepts into easily digestible modules. Her exceptional communication skills and engaging teaching methods create an inclusive and collaborative learning environment that fosters growth and knowledge sharing among participants.\r\n\r\nBeyond her training expertise, Sophia is also a sought-after consultant for real estate firms, offering strategic guidance and customized solutions to optimize property portfolios, streamline operations, and maximize returns on investments. Her deep understanding of market dynamics, industry trends, and emerging technologies allows her to provide valuable advice to clients seeking to stay ahead in a competitive market.\r\n\r\nSophia\'s passion for real estate and dedication to excellence shine through in every aspect of her work. Her commitment to ongoing professional development ensures that her training programs remain up-to-date and relevant to the evolving needs of the industry.\r\n\r\nWhether you are a seasoned real estate professional looking to sharpen your skills or a newcomer seeking a comprehensive understanding of real estate management, Sophia Reynolds is the trainer who can guide you on your path to success. Join her transformative training programs and unlock your full potential in the dynamic world of real estate management.', NULL, 17, 27, 29, 36, 0x000000000101000000cb37fdc1618e3c408abc2353c14d5340, b'010', 'all', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, NULL, NULL, 10, 1, 1, 0, NULL, NULL, 0, NULL, 1605463391, NULL, 1622030241),
(930, 'Jade Harrison', 'user', 1, NULL, '+12025550130', 'jadeharrison@gmail.com', NULL, '$2y$10$NPgvpOF52CHJuSKbh9gG8.7IvjjFd0HklLy5elWySZ58m.9IHpM2K', NULL, NULL, 'Ci4PVF45uuqLCuaxz92kWYuFMnTyesfS5N9cMaGnCsTrkb6zQF5UL8suOFrk', 0, 0, 0, 0, 1, 0, 0, NULL, '/store/930/avatar/617a4ee75dd14.png', NULL, '/store/930/2.jpg', NULL, NULL, '46 Place Charles de Gaulle', 16, 22, 23, 24, NULL, NULL, 'all', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, '/store/930/passport.jpg', '/store/930/certificate.jpg', NULL, 1, 0, 0, NULL, NULL, 0, NULL, 1606325331, NULL, NULL),
(934, 'Benjamin Harper', 'teacher', 4, 4, '+12025550143', 'Lindaanderson_92@gmail.com', 'Benjamin Harper', '$2y$10$j9Nm25IZB/AmPJOP0xHD..eY07S92w5CZvzFjd8K2mSnEZPkEb8Te', NULL, NULL, 'K3NlY69opvJgm1s6n44XHVYkqciY6dvUOmsbqQojBMFzxVS5DqI0hwL8v2r4', 0, 1, 1, 0, 1, 0, 0, NULL, '/store/1/posts/painter.png', NULL, '/store/1/posts/15.05.2023_20.49.57_REC.png', NULL, 'Benjamin Harper is a highly skilled and experienced wall painter with a passion for creating beautiful and transformative spaces. With over a decade of professional experience, Benjamin has established himself as a go-to expert in the field of interior and exterior painting.\r\n\r\nKnown for his meticulous attention to detail and commitment to delivering exceptional results, Benjamin has mastered a wide range of painting techniques and applications. From residential homes to commercial properties, his expertise spans various project scales and surfaces, including walls, ceilings, trim, and specialized finishes.\r\n\r\nBenjamin\'s dedication to his craft is evident in his ability to bring clients\' visions to life. He collaborates closely with homeowners, designers, and contractors to understand their unique preferences and requirements, ensuring that every stroke of his brush aligns with their desired outcome. His keen eye for color coordination and knowledge of the latest trends enable him to create harmonious and aesthetically pleasing environments.\r\n\r\nWith a focus on professionalism and customer satisfaction, Benjamin maintains a high standard of workmanship throughout every project. He prioritizes clear communication, adheres to project timelines, and employs top-quality materials to ensure durable and long-lasting finishes. Benjamin\'s expertise extends beyond painting techniques, as he also offers valuable advice on surface preparation, paint selection, and maintenance to maximize the longevity of his work.\r\n\r\nAs a respected wall painter, Benjamin continuously hones his skills and stays updated with industry advancements. He actively seeks out training and workshops to stay at the forefront of emerging trends, innovative painting techniques, and eco-friendly practices.\r\n\r\nWhether you\'re looking to refresh the walls of your home, create a striking feature wall, or enhance the aesthetics of your commercial space, Benjamin Harper is the painter to trust. With his artistic flair, technical expertise, and unwavering commitment to excellence, Benjamin will transform your space into a masterpiece that surpasses your expectations.', 'OX7 3NH, England, Oxfordshire, Ascott-under-Wychwood', 19, 59, 60, 63, 0x0000000001010000002e7710c1ce2f284043a4cb6cec292e40, b'100', 'all', 'active', 1, 0, 'EN', NULL, 'America/New_York', 0, 0, '/store/934/passport.jpg', '', NULL, 1, 1, 0, NULL, NULL, 0, NULL, 1612680476, NULL, NULL),
