INSERT INTO `webinar_translations` (`id`, `webinar_id`, `locale`, `title`, `seo_description`, `description`) VALUES
(44, 2010, 'en', 'Home Decoration Course with Certificate', 'Decorate your home with this course and find the best job', '<p><font style=\"color: rgb(0, 0, 0); font-weight: 700;\"><br></font><font style=\"color: rgb(0, 0, 0); font-weight: 700;\">Interior design courses are gaining interest in today’s world. Many of us have dreams of becoming interior designers, but simply do not have the time. Also, with the high tuition expenses of conventional education, online education is becoming a more popular alternative every day. As a matter of fact, much evidence is showing that online learning could be just as effective as real-life, face-to-face education. Luckily, you do not have to postpone your dreams till you magically have the money or time to pursue them. Here, we have gathered 10 online interior design courses for you busy bees out there who want to learn the basics of interior design for the comfort of your own homes. If you are looking for tips for a specific home zone, you can check this guide on How to Design Kitchen Interiors.</font><font style=\"color: rgb(0, 0, 0); font-weight: 700;\"><br></font><font style=\"color: rgb(0, 0, 0); font-weight: 700;\">Also, practicing interior designers who would like to further expand their knowledge, check the advanced courses on the list.</font></p>'),
